// Localized article bodies (paragraph arrays) per slug. Filled in language by
// language; any slug/lang not present here falls back to the English body.
export const articleBody: Record<string, Partial<Record<Lang, string[]>>> = {
  'adhd-rejection-sensitive-dysphoria': {
    de: [
      `Rejection Sensitive Dysphoria, kurz RSD, ist der intensive emotionale Schmerz, der auf echte oder vermeintliche Ablehnung, Kritik oder Misserfolg folgt. Für viele Menschen mit ADHS ist es das störendste Symptom von allen, und doch wird fast niemand bei der Diagnose davor gewarnt. Eine beiläufige Bemerkung einer Kollegin, eine Nachricht, die unbeantwortet bleibt, oder ein winziger Fehler bei der Arbeit kann jeweils eine Welle von Schmerz auslösen, die sich körperlich anfühlt und in keinem Verhältnis zu dem steht, was tatsächlich passiert ist.`,
      `Der Grund ist neurologisch, keine Frage von Dünnhäutigkeit. ADHS-Gehirne regulieren Emotionen anders, und Gefühle kommen tendenziell schneller, lauter und schwerer abschaltbar. Dieselben Dopamin- und Noradrenalin-Systeme, die das Fokussieren erschweren, machen auch die emotionale Intensität schwerer herunterzuregeln – wo eine neurotypische Person einen kleinen Stich spürt, kann ein ADHS-Gehirn innerhalb von Sekunden etwas erleben, das echter Verzweiflung näherkommt.`,
      `RSD trägt viele verschiedene Verkleidungen. Manchmal sieht es aus wie People-Pleasing, bei dem du zu allem Ja sagst, damit niemand je von dir enttäuscht ist. Manchmal sieht es aus wie Perfektionismus oder das stille Vermeiden von Dingen, bei denen du scheitern könntest. Manchmal kippt es nach außen in plötzliche Wut oder Abwehr. Und sehr oft sieht es aus wie Rückzug: Pläne absagen, Feedback meiden oder dich von Menschen zurückziehen, sobald du spürst, dass du beurteilt werden könntest.`,
      `Weil der Schmerz unsichtbar ist, wird Menschen mit RSD oft gesagt, sie würden überreagieren oder seien dramatisch. Diese Reaktion macht alles schlimmer, weil sie Scham auf ein ohnehin überwältigendes Gefühl stapelt. Zu verstehen, dass RSD ein anerkanntes Muster innerhalb von ADHS ist und kein Charakterfehler, ist oft das Erleichterndste, was ein Mensch lernen kann, weil es endlich ein Leben voller Reaktionen erklärt, die nie Sinn zu ergeben schienen.`,
      `Was hilft, ist eine Mischung aus Benennen und Distanz. Den Moment als „das ist RSD, nicht die Wahrheit" zu erkennen, schafft einen kleinen Abstand zwischen dem Gefühl und deiner Reaktion darauf. Zu warten, bevor du auf eine auslösende Nachricht antwortest, deine Deutung an den tatsächlichen Fakten zu prüfen und dir sanfte Skripte für das Annehmen von Feedback vorzubereiten, senken alle die Intensität. Genauso hilft offenes Reden mit Menschen, denen du vertraust und die dich daran erinnern, dass ein Kommentar kein Urteil über deinen Wert ist.`,
      `Vor allem reagiert RSD auf Selbstmitgefühl statt auf Selbstkritik. Das Gefühl ist real und es ist schmerzhaft, aber es ist auch vorübergehend, und es geht schneller vorbei, wenn du ihm mit Freundlichkeit begegnest, statt es zu bekämpfen. Du bist nicht zu viel, und du bist nicht kaputt. Du hast einfach ein Gehirn, das Dinge in voller Lautstärke fühlt – und dieselbe Intensität, in eine andere Richtung gelenkt, ist oft auch dort, wo deine Wärme und Kreativität herkommen.`,
    ],
  },
  'adhd-and-sleep': {
    de: [
      `Wenn dein Gehirn in dem Moment lebendig wird, in dem dein Kopf das Kissen berührt, bist du alles andere als allein. Schlafprobleme gehören zu den häufigsten und am wenigsten besprochenen Seiten von ADHS und betreffen eine große Mehrheit der Erwachsenen mit dieser Diagnose. Das Muster ist schmerzhaft vertraut: den ganzen Tag erschöpft, dann plötzlich nachts hellwach, mit einem Kopf, der durch Gespräche, Ideen, Sorgen und die To-do-Liste von morgen rast – genau dann, wenn du ihn am dringendsten still bräuchtest.`,
      `Ein Teil davon ist schlicht biologisch. Viele Menschen mit ADHS haben einen verschobenen zirkadianen Rhythmus, was bedeutet, dass ihr natürliches Schlafsignal ein paar Stunden später eintrifft, als der Rest der Welt es erwartet. Hinzu kommt, dass das ADHS-Gehirn unterstimuliert ist, wenn es nichts zu tun gibt, sodass sich die Stille der Schlafenszeit eher unerträglich als erholsam anfühlt und der Geist nach Stimulation sucht – in Form von rasenden Gedanken oder noch einer Folge.`,
      `Hier kommt der berüchtigte zweite Wind ins Spiel. Gerade wenn dein Körper endlich bereit ist herunterzufahren, taucht ein Energie- oder Fokusschub auf, und plötzlich putzt du um Mitternacht gründlich die Küche oder beginnst ein Projekt. Forschende nennen das weitere Muster manchmal Revenge Bedtime Procrastination: Wenn der Tag dir keine Zeit gelassen hat, die sich nach dir anfühlt, wird die späte Nacht zum einzigen Fenster für Freiheit – und der Schlaf verliert leise.`,
      `Die Morgen zahlen dann den Preis. ADHS-Gehirne erleben oft eine intensive Schlafträgheit, jenen schweren, nebligen Zustand, der das Aufstehen fast unmöglich macht, egal wie viele Wecker gestellt sind. Das ist keine Faulheit und kein moralisches Versagen. Es ist das vorhersehbare Ergebnis eines Gehirns, das viel zu spät eingeschlafen ist und nun auf einem Zeitplan aufwachen soll, der für die innere Uhr von jemand anderem gemacht wurde.`,
      `Was hilft, ist sanft und beständig statt streng. Eine Einschlafroutine, die früher beginnt, als nötig scheint, ein Brain Dump auf Papier, um die rasenden Gedanken vor dem Schlafen zu leeren, gedämpftes Licht am Abend und helles Licht am Morgen sowie eine Aufstehzeit, die auch am Wochenende ungefähr gleich bleibt, schieben den Rhythmus alle zurück an seinen Platz. Die Aufgaben von morgen zu externalisieren, damit dein Gehirn darauf vertraut, dass sie sicher festgehalten sind, ist oft der Unterschied zwischen Wachliegen und Loslassen.`,
      `Sei geduldig mit dir, während du experimentierst, denn Schlaf wird selten in einer einzigen Nacht repariert. Das Ziel ist keine perfekte Lehrbuch-Schlafhygiene; es ist eine Handvoll kleiner, wiederholbarer Gewohnheiten, die das Einschlafen ein wenig leichter und die Morgen ein wenig freundlicher machen. Mit deiner inneren Uhr zu arbeiten statt gegen sie ist weit nachhaltiger, als einen Zeitplan zu erzwingen, der nie für ein ADHS-Gehirn gebaut wurde.`,
    ],
  },
  'body-doubling-adhd': {
    de: [
      `Ist dir schon aufgefallen, wie viel leichter dir Dinge von der Hand gehen, wenn einfach jemand anderes im Raum ist? Genau das ist die Idee hinter Body Doubling, einer der zuverlässigsten Fokus-Strategien für ADHS-Gehirne. Ein Body Double ist eine Person, die neben dir arbeitet – nicht bei deiner Aufgabe hilft, sondern nur anwesend ist – und deren ruhige Gegenwart die unmögliche Aufgabe irgendwie plötzlich machbar macht.`,
      `Es funktioniert, weil ADHS im Kern eine Herausforderung der Selbstregulation ist und nicht des Wissens. Meist weißt du genau, was zu tun ist; das Schwierige ist das Anfangen und Dranbleiben. Eine andere Person dort zu haben, schafft sanfte äußere Verbindlichkeit und ein geliehenes Gefühl von Fokus, und es fügt gerade genug Neuheit und milde soziale Präsenz hinzu, um deinem Gehirn den Dopamin-Schubs zu geben, den es zum Beginnen und Weitermachen braucht.`,
      `Body Doubling gibt es in vielen Formen, du kannst also wählen, was zu deinem Leben passt. Es kann eine Freundin sein, die auf dem Sofa liest, während du Papierkram sortierst, ein Partner, der kocht, während du aufräumst, oder ein Videoanruf, bei dem zwei Menschen in Stille an völlig getrennten Dingen arbeiten. Es gibt auch eigene virtuelle Coworking-Plattformen und ADHS-freundliche Fokus-Apps, bei denen du dich einer Sitzung mit Fremden anschließt und einfach parallel arbeitest.`,
      `Die Einrichtung ist erfrischend einfach. Entscheide, woran du arbeiten wirst, sag deinem Body Double, was du beginnst, einigt euch auf eine Zeitspanne und fangt dann gemeinsam an. Ein kurzer Check-in am Ende, bei dem ihr benennt, was jede und jeder geschafft hat, schließt den Kreis und beschert ein kleines Gefühl von Zufriedenheit. Entscheidend ist, dass dich niemand beaufsichtigt oder bewertet; der Zauber liegt rein in der geteilten Anwesenheit.`,
      `Body Doubling glänzt genau bei den Aufgaben, die ADHS-Gehirne am meisten meiden: langweiliger Papierkram, Putzen, E-Mail-Rückstände, Formulare ausfüllen und alles, was seit Wochen unangetastet liegt. Es geht weniger um die Fähigkeiten der anderen Person und mehr darum, den Bann des Vermeidens zu brechen – deshalb kann selbst ein nahezu stiller Begleiter, der nichts von deiner Arbeit versteht, völlig verändern, was du zu erledigen schaffst.`,
      `Wenn du immer schon besser in einem belebten Café gearbeitet oder dich seltsam produktiv gefühlt hast, wenn eine Freundin in der Nähe war, dann macht Body Doubling aus diesem Instinkt einfach ein Werkzeug, nach dem du bewusst greifen kannst. Es ist keine Krücke und kein Schummeln. Es ist eine kluge Anpassung, die mit der Verdrahtung deines Gehirns arbeitet, und viele erleben es als eine ihrer verlässlichsten Arten, anzufangen.`,
    ],
  },
  'adhd-burnout': {
    de: [
      `ADHS-Burnout ist nicht dasselbe wie gewöhnliche Müdigkeit, und es ist nicht dasselbe wie alltäglicher Stress. Es ist die tiefe, den ganzen Körper erfassende Erschöpfung, die nach Monaten oder Jahren kommt, in denen ein Gehirn gezwungen wurde, auf Arten zu funktionieren, für die es nie gebaut war. Oft folgt es auf eine lange Phase des Maskierens, Überkompensierens und Sich-durch-den-Alltag-Beißens, bis eines Tages die Systeme, die kaum noch hielten, schließlich alle auf einmal versagen.`,
      `ADHS-Gehirne sind besonders anfällig dafür, weil so viel unsichtbare Anstrengung darin steckt, in Ordnung zu wirken. Erinnern, Planen, Impulse unterdrücken, Emotionen steuern und neurotypische Erwartungen erfüllen kosten alle exekutive Energie, die ohnehin knapp ist. In einem ständigen Zustand des Aufholens zu leben, erzeugt eine Art chronischen exekutiven Überziehungskredit, und irgendwann wird die Rechnung in Form von Burnout fällig.`,
      `Die Anzeichen werden leicht für etwas anderes gehalten. Aufgaben, die einst machbar waren, beginnen sich unmöglich anzufühlen, die Motivation verschwindet völlig, und selbst kleine Entscheidungen werden überwältigend. Du fühlst dich vielleicht emotional flach oder ungewöhnlich nah am Wasser gebaut, wirst öfter krank, ziehst dich von den Menschen um dich herum zurück und bemerkst, wie deine ADHS-Symptome – von Vergesslichkeit über Zeitblindheit bis Ablenkbarkeit – dramatisch schlimmer werden als sonst.`,
      `Was ADHS-Burnout so grausam macht, ist die Scham, die danebenherläuft. Viele deuten den Zusammenbruch als Beweis, dass sie faul sind oder versagen, und versuchen dann, sich mit genau der Anstrengung hindurchzuzwingen, die ihn überhaupt verursacht hat. Diese Reaktion vertieft das Loch nur, denn Burnout löst man nicht durch mehr Anstrengung; man löst es, indem man für eine Weile wirklich – und oft unbequem – weniger tut.`,
      `Erholung beginnt mit der Erlaubnis, zu ruhen, ohne es sich zu verdienen. Die Messlatte bewusst niedriger zu legen, jede nicht zwingende Verpflichtung fallenzulassen, Aufgaben zu externalisieren, damit dein Gehirn aufhören kann, sie zu halten, und um Unterstützung zu bitten, sind keine Nachgiebigkeiten; sie sind die eigentliche Behandlung. Es hilft auch, ehrlich anzuschauen, was hierher geführt hat, denn Burnout ist häufig ein Zeichen, dass dein Leben mehr von deiner exekutiven Funktion verlangt, als irgendein Gehirn nachhaltig geben kann.`,
      `Von ADHS-Burnout zu heilen geht selten schnell, und es kommt eher in Wellen als in einer geraden Linie. Sei geduldig und sanft mit dir, schütze deine Energie, als ob sie zählt – denn das tut sie wirklich –, und baue deine Routinen langsam wieder auf, mit weit mehr Raum für Ruhe, als vernünftig scheint. Das Ziel ist nicht, zurück zum Laufen auf Reserve zu kommen; es ist, ein Leben zu bauen, das den Tank gar nicht erst leert.`,
    ],
  },
  'how-to-clean-with-adhd': {
    de: [
      `Wenn dein Zuhause zwischen makellos und totalem Chaos pendelt, mit sehr wenig dazwischen, bist du nicht faul und kein Schlamper. Putzen ist für ADHS-Gehirne wirklich schwerer, weil es genau auf den Fähigkeiten sitzt, die ADHS erschwert: anfangen, in eine Reihenfolge bringen, die Aufmerksamkeit halten und sich von einer Aufgabe motivieren lassen, die keine Neuheit und sehr wenig Belohnung bietet, bis sie vollständig fertig ist.`,
      `Ein großer Teil des Kampfes ist das Alles-oder-nichts-Denken. Viele Menschen mit ADHS empfinden, dass Putzen nur zählt, wenn sie das ganze Haus perfekt machen, sodass die Aufgabe zu etwas so Riesigem anschwillt, dass das Gehirn sich weigert, überhaupt zu beginnen. Das Chaos wächst dann, bis es zur echten Krise wird, die endlich genug Dringlichkeit und Adrenalin erzeugt, um zu handeln – in einem erschöpfenden und nicht haltbaren Kreislauf.`,
      `Der Ausweg ist, den ersten Schritt fast lächerlich klein zu machen. Statt „die Küche putzen" wird die Aufgabe „einen Abschnitt der Arbeitsfläche frei räumen". Einen Timer auf nur fünf oder zehn Minuten zu stellen, wirkt Wunder, weil es deinem Gehirn einen klaren, begrenzten Endpunkt und die volle Erlaubnis gibt, aufzuhören, wenn er klingelt. Meistens ist das Anfangen der schwerste Teil, und ein wenig Schwung trägt dich weiter, als du erwartet hast.`,
      `Sich etwas Dopamin zu leihen, macht das Ganze leichter. Eine Lieblings-Playlist, ein fesselnder Podcast oder ein Hörbuch verwandeln eine langweilige Aufgabe in etwas Erträgliches oder sogar Angenehmes. Body Doubling hilft auch, denn neben einer Freundin, einem Partner oder sogar bei einem Videoanruf zu putzen, hält dich verankert, und dir selbst eine kleine, konkrete Belohnung am Ende zu versprechen, gibt deinem Gehirn etwas Greifbares, worauf es zugehen kann.`,
      `Es hilft auch, einen Reset statt einen Grundputz anzustreben. Dein Ziel ist an den meisten Tagen einfach, den Raum wieder funktional zu machen, nicht magazin-perfekt, und „gut genug" ist eine völlig legitime Ziellinie. Putzutensilien sichtbar und griffbereit zu halten, deine Ansprüche bewusst zu senken und einen Raum oder sogar eine Fläche nach der anderen anzugehen, verringern alle die Reibung, die dich vom Anfangen abhält.`,
      `Am wichtigsten: lass das moralische Gewicht los, das du an ein aufgeräumtes Zuhause geknüpft hast. Ein unordentlicher Raum ist kein Beweis für einen unordentlichen Charakter; er ist schlicht ein Zeichen, dass Standard-Putztipps nie für die Art gemacht waren, wie dein Gehirn funktioniert. Mit winzigen Schritten, einem Timer, etwas Dopamin und sehr viel weniger Scham wird ein ruhigeres Zuhause weit erreichbarer – und ein sanfter Planer, der die Arbeit in kleine Stücke zerlegt, kann überraschend viel dieser Last für dich tragen.`,
    ],
  },
  'why-adhd-brains-struggle-with-planning': {
    de: [
      `Wenn du ADHS hast, fühlt sich Planung wahrscheinlich an, als würdest du Wasser in den Händen halten wollen. Du startest mit guten Vorsätzen – ein frischer Planer, ein neues System, ein optimistischer Montagmorgen – und irgendwie ist bis Dienstag schon alles wieder zerfallen. Das ist kein Charakterfehler. Das ist Neurowissenschaft.`,
      `ADHS betrifft den präfrontalen Kortex, den Teil des Gehirns, der für die exekutiven Funktionen zuständig ist – Planen, Priorisieren, Zeitmanagement und das Beginnen von Aufgaben. Wenn dieses System nicht so funktioniert wie bei neurotypischen Menschen, helfen herkömmliche Planungsmethoden nicht nur nicht. Sie machen es sogar schlimmer.`,
      `Herkömmliche Planer setzen voraus, dass du auf eine Liste schaust und dich motiviert fühlst, anzufangen. Für ADHS-Gehirne funktioniert Motivation nicht so. ADHS-Gehirne werden von Interesse, Dringlichkeit, Neuheit und Herausforderung angetrieben – nicht von Wichtigkeit oder Priorität. Eine Aufgabe kann entscheidend wichtig sein und sich trotzdem unmöglich anfühlen, während eine völlig belanglose, aber interessante Aufgabe sofort erledigt wird.`,
      `Zeitblindheit ist ein weiterer wichtiger Faktor. Die meisten Menschen haben eine innere Uhr, die ihnen hilft, das Vergehen der Zeit zu spüren. ADHS-Gehirnen fehlt das oft – was dazu führt, dass man plötzlich merkt, dass Stunden vergangen sind, oder dass eine Deadline morgen ist, obwohl sie sich wie Wochen entfernt anfühlte.`,
      `Was hilft wirklich? Systeme, die mit diesen Mustern arbeiten statt gegen sie. Energiebasierte Planung (Aufgaben nach deinem natürlichen Energielevel planen). Time-Timer (visuelle Darstellungen des Vergehens der Zeit). Body Doubling (an der Seite einer anderen Person arbeiten). Und die Schamspirale auflösen, die aus dem Scheitern eines Systems entsteht – denn genau diese Scham macht das Anfangen oft noch schwerer.`,
      `Das Ziel ist nicht, dein ADHS-Gehirn zu reparieren. Das Ziel ist, ein Leben zu bauen, das zu dem Gehirn passt, das du hast.`,
    ],
  },
  'dopamine-menu-guide': {
    de: [
      `Ein Dopamin-Menü ist genau das, wonach es klingt: eine kuratierte Liste von Aktivitäten, die deinem Gehirn einen Dopamin-Schub geben, aufgebaut wie eine Speisekarte. Schnelle Kicks. Mittlere Pausen. Optionen zum vollständigen Aufladen. Die Idee ist einfach, aber für ADHS-Gehirne kann sie wirklich lebensverändernd sein.`,
      `ADHS ist in vielerlei Hinsicht eine Störung der Dopaminregulation. Das Gehirn produziert oder verarbeitet Dopamin nicht auf die typische Weise – deshalb suchen ADHS-Gehirne ständig nach Stimulation, Neuheit und Belohnung. Ohne genug Dopamin fühlt sich das Beginnen von Aufgaben unmöglich an. Die Konzentration verflüchtigt sich. Die Motivation verschwindet völlig.`,
      `Ein Dopamin-Menü gibt dir eine vorgeplante, schuldfreie Möglichkeit, deinen Dopaminspiegel zu regulieren. Statt Doomscrolling oder impulsiv eine ganze Tüte Chips zu essen (beides völlig nachvollziehbares dopaminsuchendes Verhalten), hast du Optionen bereit. Optionen, die du gewählt hast, als dein Gehirn in einem guten Zustand war – nicht, als es verzweifelt war.`,
      `So baust du deins: Beginne damit, Aktivitäten aufzulisten, die dich wirklich aufleuchten lassen. Nicht Dinge, die du genießen solltest – Dinge, die tatsächlich wirken. In der Küche tanzen. Ein bestimmter YouTube-Kanal. Ein Fünf-Minuten-Spaziergang. Einer Freundin etwas Nettes schreiben. Ordne sie dann nach Zeit- und Energieaufwand.`,
      `Schnelle Kicks (1–5 Minuten): Dinge, die du zwischen Aufgaben tun kannst, ohne den Schwung zu verlieren. Mittlere Pausen (10–20 Minuten): echte Erholungszeit. Tiefes Aufladen (30+ Minuten): für die Momente, in denen du wirklich erschöpft bist. Der Schlüssel ist, die Liste bereit zu haben, bevor du sie brauchst – denn wenn das Dopamin niedrig ist, fällt das Entscheiden noch schwerer.`,
      `Druck sie aus. Häng sie irgendwo gut sichtbar auf. Und denk daran: dein Dopamin-Menü zu nutzen, ist kein Aufschieben. Es ist Pflege.`,
    ],
  },
  'time-blindness-adhd': {
    de: [
      `Zeitblindheit gehört zu den am meisten missverstandenen Aspekten von ADHS. Es ist nicht so, dass Menschen mit ADHS sich nicht um Zeit kümmern, dass sie verantwortungslos wären oder sich einfach „mehr anstrengen" müssten. Zeitblindheit ist neurologisch – das ADHS-Gehirn erlebt Zeit wirklich anders.`,
      `Dr. Russell Barkley, einer der führenden ADHS-Forscher, beschreibt es so: Die meisten Menschen erleben Zeit als einen kontinuierlichen Fluss, den sie spüren können. ADHS-Gehirne neigen dazu, nur zwei Zeiten zu erleben: jetzt und nicht jetzt. Der Abstand zwischen „in einer Stunde" und „in drei Wochen" ist im Grunde derselbe – beides ist „nicht jetzt".`,
      `Das erklärt so vieles. Warum Deadlines weit weg wirken und dann plötzlich zu nah sind. Warum sich 20 Minuten unter der Dusche wie 5 anfühlen. Warum du nicht spürst, dass du zu spät dran bist, bis du schon sehr spät dran bist. Warum Hyperfokus Stunden verschlingen kann, ohne dass du es merkst.`,
      `Was hilft? Zeit sichtbar machen. Eine große analoge Uhr an deinem Arbeitsplatz. Ein Time-Timer (ein visueller Timer, der das Vergehen der Zeit als schrumpfenden roten Bogen zeigt). Wecker stellen – nicht nur für den Moment, in dem du los musst, sondern auch für 30 Minuten vorher, 15 Minuten vorher. In zeitlich begrenzten Blöcken arbeiten statt in offenen Sitzungen.`,
      `Übergangswarnungen helfen ebenfalls enorm – gib dir selbst eine Vorwarnung von 5 Minuten, bevor du die Aufgabe wechselst, statt zu erwarten, dass dein Gehirn sofort umschaltet. Viele ADHS-Gehirne empfinden Übergänge als wirklich schmerzhaft, und ein Teil davon ist der abrupte Sprung vom „jetzt" hin zu der plötzlichen Notwendigkeit, „nicht jetzt"-Aufgaben anzuerkennen.`,
      `Zeitblindheit ist real. Sie ist keine Ausrede – sie ist ein Symptom. Und wie alle ADHS-Symptome reagiert sie am besten auf Anpassung statt auf Bestrafung.`,
    ],
  },
  'habit-stacking-adhd': {
    de: [
      `Die meisten Ratschläge zu Gewohnheiten sind für neurotypische Gehirne gemacht. Mach es 21 Tage lang jeden Tag, und es wird automatisch. Wähle einen Auslöser, eine Routine und eine Belohnung. Bau deine Willenskraft auf. Für ADHS-Gehirne scheitern diese Ratschläge oft völlig – nicht weil der Rat falsch wäre, sondern weil er einen konstanten, vorhersehbaren inneren Zustand voraussetzt, den ADHS schlicht nicht liefert.`,
      `Habit Stacking ist anders. Statt zu versuchen, isolierte Gewohnheiten durch Wiederholung aufzubauen, knüpfst du neue Verhaltensweisen an bestehende. Die bestehende Gewohnheit wird zum Auslöser. Das funktioniert für ADHS-Gehirne viel besser, weil es eine der größten Hürden beseitigt: sich daran zu erinnern, das Ding überhaupt zu tun.`,
      `Die wichtigste Anpassung für ADHS ist, kleiner anzufangen, als du denkst. Peinlich klein. Das Ziel einer neuen Gewohnheit ist nicht, jeden Tag die ganze Sache zu tun – sondern das Verhalten automatisch zu machen. Eine Ein-Minuten-Gewohnheit, die du jeden Tag tust, ist unendlich wertvoller als eine 20-Minuten-Gewohnheit, die du dreimal tust und dann aufgibst.`,
      `Knüpf deine neue Gewohnheit an etwas, das ohnehin zuverlässig passiert. Nachdem ich meinen Morgenkaffee gemacht habe → schreibe ich drei Vorsätze für den Tag. Nachdem ich mich an meinen Schreibtisch gesetzt habe → mache ich einen 2-minütigen Brain Dump. Nachdem ich mir abends die Zähne geputzt habe → schreibe ich die erste Aufgabe von morgen auf einen Zettel.`,
      `Rechne mit Unbeständigkeit. ADHS bedeutet, dass deine Kapazität von Tag zu Tag enorm schwankt. An schlechten Tagen sieht deine Gewohnheit vielleicht wie eine 10-Sekunden-Version aus. Das zählt trotzdem. Die Serie ist nicht der Punkt – die Richtung ist es.`,
      `Und wenn du Tage auslässt? Das ist kein Scheitern. Das ist ADHS. Die Gewohnheit zerbricht nicht durch ausgelassene Tage. Sie stirbt nur, wenn du entscheidest, dass sie tot ist. Fang einfach wieder an. Jeder Tag ist eine neue Chance, das Leben aufzubauen, zu dem dein Gehirn fähig ist.`,
    ],
  },
  'do-i-have-adhd-test': {
    de: [
      `Wenn du dich um 1 Uhr nachts dabei ertappt hast, „habe ich ADHS" zu googeln, bist du in guter Gesellschaft. Für sehr viele Erwachsene – besonders Frauen und Menschen, die in der Schule gut waren – kommt die Frage erst auf, wenn das Leben kompliziert genug wird, dass die Bewältigungsstrategien nicht mehr greifen. Ein fordernder Job, Elternschaft oder einfach das eigene Leben zu führen kann lebenslange Muster plötzlich unübersehbar machen.`,
      `ADHS bei Erwachsenen sieht selten aus wie das Klischee eines hyperaktiven Kindes, das von den Wänden abprallt. Es sieht aus wie ein brillanter Mensch, der den Bericht nicht anfangen kann, der morgen fällig ist. Es sieht aus wie das Vergessen von Terminen trotz drei Erinnerungen, vierzig offene Browser-Tabs und hundert weitere im Kopf, und die Erschöpfung durch Aufgaben, die für alle anderen mühelos scheinen. Der Kampf ist real, und er ist keine Frage der Willenskraft.`,
      `Es gibt drei Erscheinungsformen. Der vorwiegend unaufmerksame Typ dreht sich um Konzentration, Gedächtnis und Organisation – das „in Gedanken verloren"-Muster, das oft völlig übersehen wird. Der vorwiegend hyperaktiv-impulsive Typ dreht sich um Unruhe, Impulsivität und emotionale Intensität – das „immer an"-Muster. Der kombinierte Typ, der am häufigsten ist, bedeutet, dass du deutliche Merkmale aus beiden erlebst, und das Gleichgewicht kann sich je nach Stress, Umgebung und der Aufgabe vor dir verschieben.`,
      `Ein paar Anzeichen tauchen immer wieder auf: Schwierigkeiten, Aufgaben zu beginnen, selbst wenn du sie wirklich tun willst, Zeitblindheit (Deadlines wirken weit weg und sind dann plötzlich da), ständig Dinge verlieren, Hyperfokus auf das, was dich interessiert, während alles andere liegen bleibt, und ein Nervensystem, das intensiver reagiert, als die Situation zu verlangen scheint. Keines davon allein bedeutet ADHS – aber ein beständiges Bündel über Jahre hinweg ist es wert, dass man hinschaut.`,
      `Eine Selbsteinschätzung kann dich nicht diagnostizieren, und das sollte sie auch nicht versuchen. Was eine gute Einschätzung tun kann: dir helfen, Muster in Worte zu fassen, die du seit Jahren spürst, aber nie benannt hast, und dir etwas Konkretes geben, das du zu einer Fachperson mitnehmen kannst. Unser kostenloser ADHS-Test führt dich durch 40 Fragen auf Basis der DSM-5-Kriterien und zeigt dir, zu welchem Typ deine Antworten tendieren – in etwa fünf Minuten, ohne Scham und ohne Fachjargon.`,
      `Wenn dich deine Ergebnisse ansprechen, ist der nächste Schritt ein Gespräch mit einer approbierten Psychiaterin oder einem Psychologen, die eine echte Abklärung vornehmen und Optionen besprechen können. Sei in der Zwischenzeit sanft mit dir. Zu verstehen, wie dein Gehirn funktioniert, heißt nicht, etwas Falsches an dir zu finden – es heißt, endlich ein Leben bauen zu dürfen, das zu dem Gehirn passt, das du tatsächlich hast.`,
    ],
  },
  'adhd-paralysis': {
    de: [
      `ADHS-Paralyse gehört zu den frustrierendsten und am wenigsten verstandenen Seiten von ADHS. Es ist die Erfahrung, genau zu wissen, was du tun musst, es wirklich tun zu wollen, die Folgen des Nichtstuns zu verstehen – und trotzdem völlig unfähig zu sein, anzufangen. Du bist nicht faul. Du vermeidest es nicht absichtlich. Du bist erstarrt.`,
      `Es gibt ein paar Spielarten davon. Aufgaben-Paralyse ist die Unfähigkeit, eine einzelne Aufgabe zu beginnen. Entscheidungs-Paralyse trifft, wenn es zu viele Optionen gibt und dein Gehirn sich schlicht weigert, eine zu wählen. Und Überforderungs-Paralyse stellt sich ein, wenn alles gleich dringend wirkt, sodass du am Ende gar nichts tust – oft begleitet von starker Schuld. Alle drei kommen vom selben Ort: einem exekutiven System, das vorübergehend überlastet ist.`,
      `Die Neurowissenschaft erklärt, warum „mach es einfach" nie funktioniert. Eine Aufgabe zu beginnen verlangt vom Gehirn, den Aufwand abzuschätzen, Schritte zu ordnen und genug Dopamin zu erzeugen, um die Bewegung anzustoßen. In ADHS-Gehirnen ist dieses Anstoß-System unzuverlässig. Wenn eine Aufgabe groß, langweilig oder unklar wirkt, kann das Gehirn die Aktivierungsenergie nicht aufbringen – und je mehr du drückst, desto stärker blockiert es.`,
      `Der Ausweg ist fast nie, härter zu drücken. Es ist, den ersten Schritt absurd klein zu machen. Nicht „die Küche putzen", sondern „eine Tasse in die Spüle stellen". Nicht „den Bericht schreiben", sondern „das Dokument öffnen und den Titel tippen". Das Ziel ist nicht, fertig zu werden – es ist, die Starre zu durchbrechen. Bewegung erzeugt Dopamin, und Dopamin macht den nächsten Schritt möglich. Deshalb fühlt sich Schwung so gut an, sobald er einmal beginnt.`,
      `Was sonst noch wirklich hilft: Body Doubling, bei dem du neben einer anderen Person arbeitest (auch per Videoanruf), damit dein Gehirn sich deren Fokus ausleiht. Die Schritte externalisieren, damit sie auf Papier leben statt im Kopf zu kreisen. Einen Timer auf nur fünf Minuten stellen, mit der ausdrücklichen Erlaubnis, danach aufzuhören. Und ein Brain Dump, um das mentale Durcheinander zu klären, bevor du wählst, was zählt. Jedes davon senkt die Aktivierungsenergie, die die Aufgabe verlangt.`,
      `Vor allem: lass die Scham los. Paralyse ist ein Symptom, kein Charakterfehler, und Scham ist Brennstoff für die Starre – sie lässt die Aufgabe noch bedrohlicher wirken, was dein Gehirn noch fester blockiert. Das Freundlichste und Wirksamste, was du tun kannst, ist, einen festgefahrenen Moment als Information zu behandeln, den Schritt zu verkleinern und dir zu erlauben, schlecht anzufangen. Schlecht anzufangen zählt trotzdem als Anfangen.`,
    ],
  },
  'best-planner-for-adhd': {
    de: [
      `Wenn du einen schönen Planer gekauft, ihn neun Tage lang gewissenhaft genutzt und dann zugesehen hast, wie er zum teuren Briefbeschwerer wurde, dann war weder der Planer das Problem noch du. Die meisten Planer sind für neurotypische Gehirne gemacht – sie setzen voraus, dass du daran denkst, sie zu öffnen, dass dich eine ordentliche Liste motiviert und dass du Zeit als steten, vorhersehbaren Fluss erlebst. ADHS-Gehirne funktionieren nicht so, also bringt dich das Werkzeug leise zum Scheitern.`,
      `Ein ADHS-freundlicher Planer muss etwas anderes leisten. Er muss Zeit externalisieren, weil ADHS-Gehirne sie schwer vergehen spüren. Er muss das Anfangen leicht machen, weil der Aufgabenbeginn der schwierigste Teil ist. Und er muss nachsichtig sein, denn ein System, das dich für einen ausgelassenen Tag bestraft, wird in dem Moment aufgegeben, in dem du in Rückstand gerätst – was bei ADHS unvermeidlich und völlig normal ist.`,
      `Das Erste, worauf du achten solltest, ist eingebaute Aufgabenzerlegung. „Event planen" ist lähmend; „dem Veranstaltungsort schreiben, drei Termine auswählen, die Einladung entwerfen" ist machbar. Ein Planer, der dir Raum gibt, Aufgaben in winzige, konkrete Schritte zu zerlegen, beseitigt die größte Hürde, vor der ADHS-Gehirne stehen. Wenn der Planer dir nur eine leere To-do-Zeile gibt, verlangt er von deiner exekutiven Funktion genau die Arbeit, die ihr am schwersten fällt.`,
      `Das Zweite ist eine energiebasierte Struktur statt einer starren Stundenplanung. ADHS-Energie schwankt dramatisch, und ein Planer, der davon ausgeht, dass du jeden Tag pünktlich um 9 Uhr Tiefarbeit leistest, liegt an den meisten Tagen falsch. Rund um deine natürlichen Energiefenster zu planen – fordernde Aufgaben an energiereiche Zeiten, Admin an energiearme – arbeitet mit deinem Gehirn statt gegen es.`,
      `Das Dritte, und am meisten Übersehene, ist eingebaute Freundlichkeit. Die besten ADHS-Planer machen Platz für Brain Dumps, für „gut genug"-Tage, für das Feiern kleiner Erfolge und für das Neuanfangen ohne Schuld. Sie behandeln einen ausgelassenen Tag als frische Seite, nicht als gebrochene Serie. Das ist nicht weich – es ist strategisch, denn Scham ist einer der größten Gründe, warum ADHS-Systeme zusammenbrechen.`,
      `Genau darum ist das bloom focus Toolkit herum gebaut: Planer, die Aufgaben für dich zerlegen, Struktur rund um Energie statt starrer Uhren, und ein Ton, der dir nie das Gefühl gibt, im Rückstand zu sein. Wenn du dir jeden aufgegebenen Planer selbst vorgeworfen hast, war es vielleicht das Design, das versagt hat – nicht deine Disziplin. Das richtige Werkzeug fühlt sich weniger wie ein Test an, den du immer wieder nicht bestehst, und mehr wie eine Hand in deinem Rücken.`,
    ],
  },
  'adhd-in-women': {
    de: [
      `Jahrzehntelang wurde ADHS fast ausschließlich an kleinen Jungen erforscht – den hyperaktiven, die im Unterricht nicht stillsitzen konnten. Das Ergebnis ist ein diagnostisches Bild, das verfehlt, wie ADHS bei Frauen und Mädchen am häufigsten auftritt – weshalb so viele Frauen erst mit dreißig, vierzig oder später diagnostiziert werden, häufig nachdem ein eigenes Kind abgeklärt wird und die Symptome plötzlich vertraut wirken.`,
      `Bei Frauen ist ADHS häufiger unaufmerksam als hyperaktiv – und unaufmerksames ADHS ist leise. Es stört den Unterricht nicht. Es sieht aus wie Tagträumen, wie „zerstreut" oder „schusselig" sein, wie ein kluges Mädchen, das hinter seinem Potenzial zurückbleibt. Weil es niemandem sonst Ärger macht, wird es übersehen, und das Mädchen lernt, es zu maskieren – oft zu enormen inneren Kosten.`,
      `Dieses Maskieren ist ein riesiger Teil der Geschichte. Viele Frauen mit ADHS werden zu intensiven Perfektionistinnen und Über-Vorbereiterinnen und bauen aufwendige Systeme, um ein Gehirn auszugleichen, das sie nicht verstehen. Von außen wirken sie organisiert und leistungsstark. Innen sind sie erschöpft, ängstlich und überzeugt, nur eine verrutschte Maske davon entfernt zu sein, dass alle herausfinden, wie hart sie in Wahrheit arbeiten, um mitzuhalten.`,
      `Deshalb wird ADHS bei Frauen so oft als Angst oder Depression fehldiagnostiziert. Diese Zustände können durchaus gleichzeitig bestehen – aber häufig ist die Angst eine Folge jahrelangen undiagnostizierten ADHS: der chronische Stress verpasster Deadlines, die Scham des Vergessens, der Tribut, doppelt so hart für dasselbe Ergebnis zu arbeiten. Die Angst zu behandeln, ohne das ADHS darunter zu erkennen, erfasst nur die Hälfte des Bildes.`,
      `Hormone fügen eine weitere Ebene hinzu, die die alte Forschung völlig ignoriert hat. Östrogen beeinflusst Dopamin, daher verstärken sich ADHS-Symptome oft prämenstruell, nach der Geburt und in der Perimenopause. Viele Frauen beschreiben, dass ihre Symptome mit vierzig plötzlich unbeherrschbar werden – nicht weil etwas neu falsch ist, sondern weil eine hormonelle Verschiebung den Puffer entfernt hat, auf den sie sich jahrelang unbewusst verlassen haben.`,
      `Wenn sich irgendetwas davon liest wie dein eigenes Tagebuch, dann bist du nicht kaputt, nicht dramatisch und bildest dir nichts ein. Du hast vielleicht einfach ein Gehirn, das nie zu seinen eigenen Bedingungen abgeklärt wurde. Eine Selbsteinschätzung kann dir helfen, das Muster zu benennen, und eine approbierte Fachperson kann dir eine echte Abklärung geben. Es zu verstehen ändert alles – nicht weil du ein anderer Mensch wirst, sondern weil du endlich aufhören darfst, dir selbst Vorwürfe zu machen, einer zu sein.`,
    ],
  },
}

// ---- helpers ----
export function blogTitle(slug: string, lang: Lang, enTitle: string) {
  if (lang === 'en') return enTitle
  return articleMeta[slug]?.[lang]?.title || enTitle
}
export function blogExcerpt(slug: string, lang: Lang, enExcerpt: string) {
  if (lang === 'en') return enExcerpt
  return articleMeta[slug]?.[lang]?.excerpt || enExcerpt
}
export function blogTag(enTag: string, lang: Lang) {
  if (lang === 'en') return enTag
  return blogTagMap[lang][enTag] || enTag
}
export function blogBody(slug: string, lang: Lang): string[] {
  if (lang !== 'en') {
    const t = articleBody[slug]?.[lang]
    if (t && t.length) return t
  }
  return articleContentEN[slug] || []
}
export function readTimeLabel(lang: Lang, raw: string) {
  const n = parseInt(String(raw).replace(/\D+/g, '')) || 0
  if (lang === 'de') return `${n} Min. Lesezeit`
  if (lang === 'fr') return `${n} min de lecture`
  if (lang === 'es') return `${n} min de lectura`
  return raw
}

// ---- French (FR) ----
const FR_META: Record<string, { title: string; excerpt: string }> = {
  'adhd-rejection-sensitive-dysphoria': { title: `TDAH et dysphorie sensible au rejet : pourquoi la critique fait si mal`, excerpt: `Si une petite critique peut gâcher toute ta journée, tu n'es pas trop sensible – tu vis peut-être la RSD, l'une des facettes les plus douloureuses et les moins connues du TDAH.` },
  'adhd-and-sleep': { title: `TDAH et sommeil : pourquoi ton cerveau ne s'éteint pas la nuit`, excerpt: `Pensées qui s'emballent à minuit, un second souffle pile quand tu devrais dormir, des matins impossibles – TDAH et troubles du sommeil vont de pair. Voici pourquoi, et ce qui aide.` },
  'body-doubling-adhd': { title: `Body doubling : l'astuce de concentration TDAH qui marche vraiment`, excerpt: `Pourquoi est-il tellement plus facile de travailler quand quelqu'un d'autre est dans la pièce ? Le body doubling en fait une stratégie – l'un des outils de concentration TDAH les plus fiables qui soient.` },
  'adhd-burnout': { title: `Burnout TDAH : les signes que tu tournes à vide (et comment récupérer)`, excerpt: `Le burnout TDAH n'est pas une fatigue ordinaire – c'est l'effondrement qui survient après des mois de masquage et de surcompensation. Voici comment le repérer et récupérer en douceur.` },
  'how-to-clean-with-adhd': { title: `Comment nettoyer ta maison avec un TDAH sans la surcharge`, excerpt: `Si le ménage semble impossible jusqu'à devenir une crise, tu n'es pas paresseux·se – ton cerveau a juste besoin d'une autre approche. Voici comment nettoyer avec un cerveau TDAH, pas à pas, en douceur.` },
}
for (const [slug, m] of Object.entries(FR_META)) {
  articleMeta[slug] = { ...(articleMeta[slug] || {}), fr: m }
}

const FR_BODY: Record<string, string[]> = {
  'why-adhd-brains-struggle-with-planning': [
    `Si tu as un TDAH, planifier te donne probablement l'impression d'essayer de retenir de l'eau dans tes mains. Tu commences avec de bonnes intentions – un agenda tout neuf, un nouveau système, un lundi matin optimiste – et, on ne sait comment, dès le mardi tout s'est déjà effondré. Ce n'est pas un défaut de caractère. C'est de la neuroscience.`,
    `Le TDAH touche le cortex préfrontal, la partie du cerveau responsable des fonctions exécutives – planifier, prioriser, gérer le temps et démarrer les tâches. Quand ce système ne fonctionne pas comme chez les personnes neurotypiques, les méthodes de planification classiques ne se contentent pas d'être inutiles. Elles aggravent activement les choses.`,
    `Les agendas classiques supposent que tu peux regarder une liste et te sentir motivé·e à commencer. Pour les cerveaux TDAH, la motivation ne fonctionne pas ainsi. Les cerveaux TDAH sont mus par l'intérêt, l'urgence, la nouveauté et le défi – pas par l'importance ou la priorité. Une tâche peut être cruciale et sembler malgré tout impossible à démarrer, tandis qu'une tâche totalement accessoire mais intéressante se fait immédiatement.`,
    `La cécité temporelle est un autre facteur majeur. La plupart des gens ont une horloge interne qui les aide à sentir le temps passer. Les cerveaux TDAH en sont souvent dépourvus – d'où l'expérience de se rendre compte soudain que des heures ont filé, ou qu'une échéance est pour demain alors qu'elle semblait à des semaines.`,
    `Qu'est-ce qui aide vraiment ? Des systèmes qui travaillent avec ces schémas plutôt que contre eux. La planification basée sur l'énergie (organiser les tâches selon tes niveaux d'énergie naturels). Les minuteurs visuels (des représentations du temps qui s'écoule). Le body doubling (travailler aux côtés de quelqu'un d'autre). Et dissoudre la spirale de honte qui naît de l'échec d'un système – parce que c'est souvent cette honte qui rend le démarrage encore plus difficile.`,
    `Le but n'est pas de réparer ton cerveau TDAH. Le but est de construire une vie qui fonctionne pour le cerveau que tu as.`,
  ],
  'dopamine-menu-guide': [
    `Un menu dopamine est exactement ce que son nom indique : une liste soignée d'activités qui donnent à ton cerveau un coup de dopamine, organisée comme une carte de restaurant. Des doses rapides. Des pauses moyennes. Des options de recharge complète. L'idée est simple, mais pour les cerveaux TDAH, elle peut vraiment changer la vie.`,
    `Le TDAH est, à bien des égards, un trouble de la régulation de la dopamine. Le cerveau ne produit ni ne traite la dopamine de la manière habituelle – c'est pourquoi les cerveaux TDAH recherchent en permanence stimulation, nouveauté et récompense. Sans assez de dopamine, démarrer une tâche semble impossible. La concentration s'évapore. La motivation disparaît complètement.`,
    `Un menu dopamine te donne une façon préparée à l'avance, et sans culpabilité, de réguler ton niveau de dopamine. Au lieu de scroller sans fin ou d'engloutir impulsivement un paquet de chips entier (deux comportements de recherche de dopamine tout à fait compréhensibles), tu as des options prêtes. Des options que tu as choisies quand ton cerveau allait bien, pas quand il était à bout.`,
    `Comment créer le tien : commence par lister des activités qui t'illuminent vraiment. Pas des choses que tu penses devoir apprécier – des choses qui fonctionnent réellement. Danser dans ta cuisine. Une chaîne YouTube précise. Une marche de cinq minutes. Envoyer un mot gentil à une amie. Classe-les ensuite selon le temps et l'énergie qu'elles demandent.`,
    `Doses rapides (1 à 5 minutes) : des choses à faire entre deux tâches sans perdre ton élan. Pauses moyennes (10 à 20 minutes) : un vrai temps de recharge. Recharge profonde (30 minutes et plus) : pour les moments où tu es réellement vidé·e. La clé est d'avoir la liste prête avant d'en avoir besoin – car lorsque la dopamine est basse, décider est encore plus dur.`,
    `Imprime-la. Mets-la quelque part bien en vue. Et souviens-toi : utiliser ton menu dopamine, ce n'est pas procrastiner. C'est de l'entretien.`,
  ],
  'time-blindness-adhd': [
    `La cécité temporelle est l'un des aspects les plus mal compris du TDAH. Ce n'est pas que les personnes avec un TDAH se moquent du temps, qu'elles soient irresponsables ou qu'elles aient juste besoin de « faire plus d'efforts ». La cécité temporelle est neurologique – le cerveau TDAH vit vraiment le temps différemment.`,
    `Le Dr Russell Barkley, l'un des grands chercheurs sur le TDAH, le décrit ainsi : la plupart des gens vivent le temps comme un flux continu qu'ils peuvent ressentir. Les cerveaux TDAH ont tendance à ne vivre que deux temps : maintenant, et pas maintenant. La distance entre « dans une heure » et « dans trois semaines » est au fond la même – les deux sont « pas maintenant ».`,
    `Cela explique tant de choses. Pourquoi les échéances semblent lointaines puis soudain trop proches. Pourquoi 20 minutes sous la douche en paraissent 5. Pourquoi tu ne sens pas que tu es en retard avant d'être déjà très en retard. Pourquoi l'hyperfocus peut engloutir des heures sans que tu le remarques.`,
    `Qu'est-ce qui aide ? Rendre le temps visible. Une grande horloge analogique sur ton espace de travail. Un minuteur visuel (qui montre le temps qui passe sous forme d'arc rouge qui rétrécit). Régler des alarmes non seulement pour le moment du départ, mais aussi pour 30 minutes avant, 15 minutes avant. Travailler en blocs minutés plutôt qu'en sessions ouvertes.`,
    `Les avertissements de transition aident aussi énormément – accorde-toi un préavis de 5 minutes avant de changer de tâche, au lieu d'attendre de ton cerveau qu'il bascule instantanément. Beaucoup de cerveaux TDAH trouvent les transitions vraiment douloureuses, en partie à cause du passage brutal du « maintenant » à la nécessité soudaine de reconnaître les tâches « pas maintenant ».`,
    `La cécité temporelle est réelle. Ce n'est pas une excuse – c'est un symptôme. Et comme tous les symptômes du TDAH, elle répond mieux à l'aménagement qu'à la punition.`,
  ],
  'habit-stacking-adhd': [
    `La plupart des conseils sur les habitudes sont conçus pour les cerveaux neurotypiques. Fais-le chaque jour pendant 21 jours et cela devient automatique. Choisis un déclencheur, une routine et une récompense. Renforce ta volonté. Pour les cerveaux TDAH, ces conseils échouent souvent complètement – non parce qu'ils sont faux, mais parce qu'ils supposent un état intérieur constant et prévisible que le TDAH ne fournit tout simplement pas.`,
    `L'empilement d'habitudes est différent. Au lieu d'essayer de bâtir des habitudes isolées par la répétition, tu rattaches de nouveaux comportements à des comportements existants. L'habitude déjà en place devient le déclencheur. Cela fonctionne bien mieux pour les cerveaux TDAH, car cela supprime l'un des plus grands obstacles : se souvenir de faire la chose.`,
    `L'adaptation essentielle pour le TDAH est de commencer plus petit que tu ne le penses. Petit au point d'en être gênant. Le but d'une nouvelle habitude n'est pas de faire la chose entière chaque jour – c'est de rendre le comportement automatique. Une habitude d'une minute que tu fais chaque jour vaut infiniment plus qu'une habitude de 20 minutes que tu fais trois fois avant d'abandonner.`,
    `Rattache ta nouvelle habitude à quelque chose qui se produit déjà de façon fiable. Après avoir préparé mon café du matin → j'écris trois intentions pour la journée. Après m'être assis·e à mon bureau → je fais un brain dump de 2 minutes. Après m'être brossé les dents le soir → je note la première tâche de demain sur un post-it.`,
    `Attends-toi à l'irrégularité. Le TDAH signifie que ta capacité varie énormément d'un jour à l'autre. Les mauvais jours, ton habitude ressemblera peut-être à une version de 10 secondes. Cela compte quand même. La série n'est pas l'essentiel – la direction l'est.`,
    `Et si tu sautes des jours ? Ce n'est pas un échec. C'est le TDAH. L'habitude ne se brise pas parce que tu as sauté des jours. Elle ne meurt que si tu décides qu'elle est morte. Recommence, tout simplement. Chaque jour est une nouvelle chance de bâtir la vie dont ton cerveau est capable.`,
  ],
  'do-i-have-adhd-test': [
    `Si tu t'es déjà surpris·e à taper « est-ce que j'ai un TDAH » à 1 h du matin, tu es en bonne compagnie. Pour énormément d'adultes – surtout les femmes et les personnes qui réussissaient à l'école – la question ne surgit que lorsque la vie devient assez compliquée pour que les stratégies d'adaptation cessent de fonctionner. Un travail exigeant, la parentalité ou simplement gérer sa propre vie peuvent soudain rendre des schémas de toujours impossibles à ignorer.`,
    `Chez l'adulte, le TDAH ressemble rarement au cliché de l'enfant hyperactif qui rebondit sur les murs. Il ressemble à une personne brillante incapable de commencer le rapport à rendre demain. Il ressemble à oublier des rendez-vous malgré trois rappels, à avoir quarante onglets ouverts et cent autres dans la tête, et à être épuisé·e par des tâches qui semblent sans effort pour tout le monde. La lutte est réelle, et ce n'est pas une question de volonté.`,
    `Il existe trois présentations. Le type à prédominance inattentive tourne autour de l'attention, de la mémoire et de l'organisation – le schéma « perdu dans ses pensées » qui passe souvent complètement inaperçu. Le type à prédominance hyperactive-impulsive tourne autour de l'agitation, de l'impulsivité et de l'intensité émotionnelle – le schéma « toujours en marche ». Le type combiné, le plus fréquent, signifie que tu vis des traits importants des deux, et l'équilibre peut se déplacer selon le stress, l'environnement et la tâche devant toi.`,
    `Quelques signes reviennent encore et encore : la difficulté à démarrer des tâches même quand tu veux vraiment les faire, la cécité temporelle (les échéances semblent lointaines puis arrivent d'un coup), perdre des objets sans arrêt, hyperfocaliser sur ce qui t'intéresse pendant que tout le reste glisse, et un système nerveux qui réagit plus intensément que la situation ne semble l'exiger. Aucun de ces signes seul ne signifie TDAH – mais un ensemble constant sur des années mérite qu'on y prête attention.`,
    `Une auto-évaluation ne peut pas te diagnostiquer, et elle ne devrait pas essayer. Ce qu'une bonne évaluation peut faire : t'aider à mettre des mots sur des schémas que tu ressens depuis des années sans jamais les nommer, et te donner quelque chose de concret à apporter à un·e professionnel·le. Notre test TDAH gratuit te guide à travers 40 questions fondées sur les critères du DSM-5 et te montre vers quel type tes réponses penchent – en environ cinq minutes, sans honte et sans jargon.`,
    `Si tes résultats résonnent, l'étape suivante est un échange avec un·e psychiatre ou psychologue agréé·e, qui pourra réaliser une véritable évaluation et discuter des options. En attendant, sois doux·ce avec toi-même. Comprendre comment ton cerveau fonctionne, ce n'est pas trouver quelque chose qui cloche chez toi – c'est enfin pouvoir construire une vie qui convient au cerveau que tu as vraiment.`,
  ],
  'adhd-paralysis': [
    `La paralysie TDAH est l'une des facettes les plus frustrantes et les moins comprises du TDAH. C'est l'expérience de savoir exactement ce que tu dois faire, de vouloir vraiment le faire, de comprendre les conséquences de ne pas le faire – et d'être malgré tout totalement incapable de commencer. Tu n'es pas paresseux·se. Tu ne l'évites pas exprès. Tu es figé·e.`,
    `Il en existe plusieurs variantes. La paralysie de la tâche, c'est l'incapacité de démarrer une seule tâche. La paralysie du choix frappe quand il y a trop d'options et que ton cerveau refuse simplement d'en choisir une. Et la paralysie de la surcharge survient quand tout semble également urgent, si bien que tu finis par ne rien faire du tout, souvent en ressentant une culpabilité intense. Les trois viennent du même endroit : un système exécutif momentanément surchargé.`,
    `La neuroscience aide à comprendre pourquoi « fais-le, c'est tout » ne marche jamais. Démarrer une tâche demande à ton cerveau d'estimer l'effort, d'ordonner les étapes et de générer assez de dopamine pour amorcer le mouvement. Dans les cerveaux TDAH, ce système d'amorçage est peu fiable. Quand une tâche paraît grande, ennuyeuse ou floue, le cerveau ne parvient pas à mobiliser l'énergie d'activation – et plus tu forces, plus il se bloque.`,
    `La sortie n'est presque jamais de forcer davantage. C'est de rendre le premier pas absurdement petit. Pas « nettoyer la cuisine » mais « mettre une tasse dans l'évier ». Pas « écrire le rapport » mais « ouvrir le document et taper le titre ». Le but n'est pas de finir – c'est de briser le gel. Le mouvement crée de la dopamine, et la dopamine rend le pas suivant possible. C'est pour ça que l'élan fait tellement de bien une fois lancé.`,
    `Ce qui aide vraiment aussi : le body doubling, où tu travailles aux côtés d'une autre personne (même en visio) pour que ton cerveau emprunte sa concentration. Externaliser les étapes, pour qu'elles vivent sur le papier au lieu de tourner dans ta tête. Régler un minuteur sur seulement cinq minutes, avec la pleine permission de t'arrêter ensuite. Et un brain dump pour dégager le fouillis mental avant de choisir ce qui compte. Chacun de ces gestes abaisse l'énergie d'activation que la tâche réclame.`,
    `Surtout, lâche la honte. La paralysie est un symptôme, pas un défaut de caractère, et la honte est du carburant pour le gel – elle rend la tâche encore plus menaçante, ce qui bloque ton cerveau plus fort. La chose la plus douce et la plus efficace que tu puisses faire, c'est de traiter un moment de blocage comme une information, de réduire le pas et de t'autoriser à commencer mal. Commencer mal compte quand même comme commencer.`,
  ],
  'best-planner-for-adhd': [
    `Si tu as acheté un bel agenda, l'as utilisé religieusement pendant neuf jours, puis l'as regardé devenir un presse-papier hors de prix, le problème n'était ni l'agenda ni toi. La plupart des agendas sont conçus pour les cerveaux neurotypiques – ils supposent que tu penseras à les ouvrir, qu'une liste bien rangée te motivera et que tu vis le temps comme un flux régulier et prévisible. Les cerveaux TDAH ne fonctionnent pas ainsi, alors l'outil te prépare discrètement à l'échec.`,
    `Un agenda adapté au TDAH doit faire quelque chose de différent. Il doit externaliser le temps, parce que les cerveaux TDAH le sentent mal passer. Il doit rendre le démarrage facile, parce que l'initiation des tâches est la partie la plus difficile. Et il doit être indulgent, car un système qui te punit pour un jour manqué sera abandonné dès que tu prendras du retard – ce qui, avec un TDAH, est inévitable et tout à fait normal.`,
    `La première chose à rechercher, c'est une décomposition des tâches intégrée. « Organiser un événement » est paralysant ; « écrire au lieu, choisir trois dates, rédiger l'invitation » est faisable. Un agenda qui te laisse de la place pour découper les tâches en petites étapes concrètes supprime le plus grand obstacle des cerveaux TDAH. Si l'agenda ne te donne qu'une ligne de to-do vide, il demande à ta fonction exécutive le travail qu'elle est le moins capable de faire.`,
    `La deuxième, c'est une structure basée sur l'énergie plutôt qu'un emploi du temps rigide à l'heure. L'énergie TDAH fluctue énormément, et un agenda qui suppose que tu feras un travail profond à 9 h pile chaque jour aura tort la plupart du temps. Planifier autour de tes fenêtres d'énergie naturelles – les tâches exigeantes aux moments d'énergie haute, l'administratif aux moments d'énergie basse – travaille avec ton cerveau plutôt que contre lui.`,
    `La troisième, et la plus négligée, c'est une bienveillance intégrée. Les meilleurs agendas TDAH font de la place pour les brain dumps, pour les journées « assez bien », pour célébrer les petites victoires et pour recommencer sans culpabilité. Ils traitent un jour manqué comme une page neuve, pas comme une série brisée. Ce n'est pas mièvre – c'est stratégique, car la honte est l'une des plus grandes raisons pour lesquelles les systèmes TDAH s'effondrent.`,
    `C'est exactement autour de ça qu'est construite la boîte à outils bloom focus : des agendas qui décomposent les tâches pour toi, une structure organisée autour de l'énergie plutôt que d'horloges rigides, et un ton qui ne te donne jamais l'impression d'être en retard. Si tu t'es reproché chaque agenda abandonné, c'est peut-être le design qui t'a fait défaut – pas ta discipline. Le bon outil ressemble moins à un test que tu rates sans cesse qu'à une main posée dans ton dos.`,
  ],
  'adhd-in-women': [
    `Pendant des décennies, le TDAH a été étudié presque exclusivement chez les jeunes garçons – les hyperactifs qui ne tenaient pas en place en classe. Le résultat est un tableau diagnostique qui passe à côté de la façon dont le TDAH se manifeste le plus souvent chez les femmes et les filles – c'est pourquoi tant de femmes ne sont diagnostiquées qu'à trente, quarante ans ou plus, souvent après l'évaluation de leur propre enfant, quand les symptômes deviennent soudain familiers.`,
    `Chez les femmes, le TDAH est plus souvent inattentif qu'hyperactif – et le TDAH inattentif est silencieux. Il ne perturbe pas la classe. Il ressemble à de la rêverie, à être « tête en l'air » ou « éparpillée », à une fille intelligente qui n'exploite pas son potentiel. Parce qu'il ne dérange personne d'autre, on le néglige, et la fille apprend à le masquer – souvent à un coût intérieur énorme.`,
    `Ce masquage est une part immense de l'histoire. Beaucoup de femmes avec un TDAH deviennent d'intenses perfectionnistes et sur-préparatrices, bâtissant des systèmes élaborés pour compenser un cerveau qu'elles ne comprennent pas. De l'extérieur, elles paraissent organisées et performantes. À l'intérieur, elles sont épuisées, anxieuses, et convaincues qu'un masque qui glisse suffirait pour que tout le monde découvre à quel point elles travaillent dur pour suivre.`,
    `C'est pourquoi le TDAH chez les femmes est si souvent diagnostiqué à tort comme de l'anxiété ou de la dépression. Ces troubles peuvent tout à fait coexister – mais l'anxiété est fréquemment la conséquence d'années de TDAH non diagnostiqué : le stress chronique des échéances manquées, la honte des oublis, le prix de travailler deux fois plus dur pour le même résultat. Traiter l'anxiété sans reconnaître le TDAH en dessous ne s'occupe que de la moitié du tableau.`,
    `Les hormones ajoutent une couche que l'ancienne recherche ignorait totalement. L'œstrogène influence la dopamine, donc les symptômes du TDAH s'intensifient souvent avant les règles, après l'accouchement et pendant la périménopause. Beaucoup de femmes décrivent des symptômes qui deviennent soudain ingérables vers la quarantaine – non parce que quelque chose ne va plus, mais parce qu'un changement hormonal a retiré le tampon sur lequel elles s'appuyaient inconsciemment depuis des années.`,
    `Si quoi que ce soit de tout cela se lit comme ton propre journal intime, tu n'es ni cassée, ni dramatique, ni en train d'inventer. Tu as peut-être simplement un cerveau qui n'a jamais été évalué selon ses propres termes. Une auto-évaluation peut t'aider à nommer le schéma, et un·e professionnel·le agréé·e peut te donner une véritable évaluation. Le comprendre change tout – non parce que tu deviens une autre personne, mais parce que tu peux enfin arrêter de te reprocher d'en être une.`,
  ],
  'adhd-rejection-sensitive-dysphoria': [
    `La dysphorie sensible au rejet, ou RSD, est la douleur émotionnelle intense qui suit un rejet, une critique ou un échec, réels ou perçus. Pour beaucoup de personnes avec un TDAH, c'est le symptôme le plus perturbant de tous, et pourtant presque personne n'est prévenu au moment du diagnostic. Une remarque en passant d'un collègue, un message resté sans réponse, ou une minuscule erreur au travail peuvent chacun déclencher une vague de douleur si forte qu'elle en devient physique, et totalement disproportionnée par rapport à ce qui s'est réellement passé.`,
    `La raison est neurologique, et non une question de susceptibilité. Les cerveaux TDAH régulent les émotions différemment, et les sentiments arrivent plus vite, plus fort, et sont plus difficiles à éteindre. Les mêmes systèmes de dopamine et de noradrénaline qui rendent la concentration difficile rendent aussi l'intensité émotionnelle plus dure à atténuer ; là où une personne neurotypique ressentirait une petite piqûre, un cerveau TDAH peut vivre, en quelques secondes, quelque chose de plus proche d'une véritable dévastation.`,
    `La RSD revêt de nombreux déguisements. Parfois elle ressemble à du people-pleasing, où tu dis oui à tout pour que personne ne soit jamais déçu de toi. Parfois elle ressemble à du perfectionnisme, ou au refus discret d'essayer des choses où tu pourrais échouer. Parfois elle bascule vers l'extérieur en colère ou en défense soudaines. Et très souvent elle ressemble à du retrait : annuler des projets, éviter les retours, ou t'éloigner des gens dès que tu sens que tu pourrais être jugé·e.`,
    `Parce que la douleur est invisible, on dit souvent aux personnes vivant la RSD qu'elles exagèrent ou qu'elles sont dramatiques. Cette réaction aggrave tout, car elle empile de la honte sur un sentiment déjà accablant. Comprendre que la RSD est un schéma reconnu au sein du TDAH, et non un défaut de caractère, est souvent la chose la plus soulageante qu'une personne puisse apprendre, parce qu'elle explique enfin toute une vie de réactions qui n'avaient jamais semblé avoir de sens.`,
    `Ce qui aide, c'est un mélange de nommer et de prendre du recul. Apprendre à reconnaître le moment comme « c'est la RSD, pas la vérité » crée un petit espace entre le sentiment et ta réaction. Attendre avant de répondre à un message déclencheur, confronter ton interprétation aux faits réels et préparer de douces formulations pour recevoir un retour réduisent tous l'intensité. Parler ouvertement avec des personnes de confiance aide aussi : elles peuvent te rappeler qu'un commentaire n'est pas un verdict sur ta valeur.`,
    `Surtout, la RSD répond à l'auto-compassion plutôt qu'à l'autocritique. Le sentiment est réel et il est douloureux, mais il est aussi temporaire, et il passe plus vite quand tu l'accueilles avec douceur au lieu de le combattre. Tu n'es pas « trop », et tu n'es pas cassé·e. Tu as simplement un cerveau qui ressent les choses à plein volume – et cette même intensité, orientée ailleurs, est souvent là d'où viennent aussi ta chaleur et ta créativité.`,
  ],
  'adhd-and-sleep': [
    `Si ton cerveau s'anime à l'instant où ta tête touche l'oreiller, tu es loin d'être seul·e. Les troubles du sommeil sont l'une des facettes les plus fréquentes et les moins évoquées du TDAH, touchant une large majorité des adultes concernés. Le schéma est douloureusement familier : épuisé·e toute la journée, puis soudain bien réveillé·e la nuit, avec un esprit qui galope à travers conversations, idées, soucis et la to-do de demain, exactement quand tu as le plus besoin qu'il se taise.`,
    `Une partie est purement biologique. Beaucoup de personnes avec un TDAH ont un rythme circadien décalé, ce qui signifie que leur signal de sommeil naturel arrive quelques heures plus tard que ce que le reste du monde attend. À cela s'ajoute que le cerveau TDAH est sous-stimulé quand il n'y a rien à faire, si bien que le calme du coucher peut sembler intolérable plutôt que reposant, et l'esprit part en quête de stimulation sous forme de pensées qui s'emballent ou d'un épisode de plus.`,
    `C'est là qu'intervient le fameux second souffle. Juste au moment où ton corps est enfin prêt à ralentir, une poussée d'énergie ou de concentration surgit, et te voilà à nettoyer la cuisine à fond ou à lancer un projet à minuit. Les chercheurs appellent parfois ce schéma plus large la procrastination du coucher par vengeance : quand la journée ne t'a laissé aucun temps qui te ressemble, la nuit tardive devient la seule fenêtre de liberté – et le sommeil perd en silence.`,
    `Les matins paient alors le prix. Les cerveaux TDAH connaissent souvent une inertie du sommeil intense, cet état lourd et brumeux qui rend le lever presque impossible, peu importe le nombre d'alarmes. Ce n'est pas de la paresse et ce n'est pas une faute morale. C'est le résultat prévisible d'un cerveau qui s'est endormi bien trop tard et qui doit maintenant se réveiller sur un horaire conçu pour l'horloge interne de quelqu'un d'autre.`,
    `Ce qui aide est doux et régulier plutôt que strict. Une routine d'apaisement qui commence plus tôt qu'il ne semble nécessaire, un brain dump sur papier pour vider les pensées qui s'emballent avant le coucher, une lumière plus tamisée le soir et plus vive le matin, et une heure de réveil qui reste à peu près la même même le week-end remettent peu à peu le rythme en place. Externaliser les tâches de demain pour que ton cerveau ait confiance qu'elles sont bien notées fait souvent la différence entre rester éveillé·e et lâcher prise.`,
    `Sois patient·e avec toi-même pendant que tu expérimentes, car le sommeil se répare rarement en une seule nuit. Le but n'est pas une hygiène de sommeil parfaite, comme dans les manuels ; c'est une poignée de petites habitudes répétables qui rendent l'endormissement un peu plus facile et les matins un peu plus doux. Travailler avec ton horloge interne plutôt que contre elle est bien plus durable que forcer un horaire qui n'a jamais été fait pour un cerveau TDAH.`,
  ],
  'body-doubling-adhd': [
    `As-tu déjà remarqué à quel point il est plus facile d'avancer quand quelqu'un d'autre est simplement dans la pièce ? C'est toute l'idée du body doubling, l'une des stratégies de concentration les plus fiables pour les cerveaux TDAH. Un body double est une personne qui travaille à tes côtés – sans aider à ta tâche, juste présente – et sa compagnie tranquille rend la tâche impossible soudain réalisable.`,
    `Cela fonctionne parce que le TDAH est, au fond, un défi d'autorégulation plutôt que de connaissance. En général, tu sais exactement quoi faire ; le plus dur, c'est de commencer et de tenir. Avoir une autre personne là apporte une douce responsabilité externe et un sentiment de concentration emprunté, et cela ajoute juste assez de nouveauté et de légère présence sociale pour donner à ton cerveau le coup de pouce de dopamine dont il a besoin pour démarrer et continuer.`,
    `Le body doubling existe sous de nombreuses formes, tu peux donc choisir ce qui convient à ta vie. Ce peut être une amie qui lit sur le canapé pendant que tu tries des papiers, un partenaire qui cuisine pendant que tu ranges, ou un appel vidéo où deux personnes travaillent en silence sur des choses totalement séparées. Il existe aussi des plateformes de coworking virtuel dédiées et des applis de concentration adaptées au TDAH où tu rejoins une session avec des inconnus et travailles simplement en parallèle.`,
    `La mise en place est étonnamment simple. Décide de ce sur quoi tu vas travailler, dis à ton body double ce que tu commences, mettez-vous d'accord sur une durée, puis démarrez ensemble. Un petit bilan à la fin, où vous nommez ce que chacun a terminé, boucle la boucle et offre une petite dose de satisfaction. L'essentiel, c'est que personne ne te surveille ni ne te juge ; la magie réside uniquement dans la présence partagée.`,
    `Le body doubling brille précisément pour les tâches que les cerveaux TDAH évitent le plus : l'administratif ennuyeux, le ménage, les piles d'e-mails, le remplissage de formulaires, et tout ce qui traîne intact depuis des semaines. Il s'agit moins des compétences de l'autre personne que de briser le sortilège de l'évitement – c'est pourquoi même un compagnon quasi silencieux qui ne connaît rien à ton travail peut transformer complètement ce que tu arrives à faire.`,
    `Si tu as toujours mieux travaillé dans un café animé ou si tu t'es senti·e étrangement productif·ve quand une amie était là, le body doubling transforme simplement cet instinct en un outil que tu peux mobiliser exprès. Ce n'est pas une béquille et ce n'est pas tricher. C'est un aménagement intelligent qui travaille avec le câblage de ton cerveau, et beaucoup en font l'une de leurs façons les plus fiables de commencer.`,
  ],
  'adhd-burnout': [
    `Le burnout TDAH n'est pas la même chose qu'une fatigue ordinaire, ni la même chose que le stress quotidien. C'est l'épuisement profond, de tout le corps, qui arrive après des mois ou des années à pousser un cerveau à fonctionner d'une manière pour laquelle il n'a jamais été fait. Il fait souvent suite à une longue période de masquage, de surcompensation et de serrage de dents au quotidien, jusqu'au jour où les systèmes qui tenaient à peine finissent par lâcher tous d'un coup.`,
    `Les cerveaux TDAH y sont particulièrement vulnérables, parce qu'un effort invisible énorme passe à avoir l'air d'aller bien. Se souvenir, planifier, contenir ses impulsions, gérer ses émotions et répondre aux attentes neurotypiques coûtent tous une énergie exécutive déjà rare. Vivre dans un état constant de rattrapage crée une sorte de découvert exécutif chronique, et un jour la facture tombe sous forme de burnout.`,
    `Les signes se confondent facilement avec autre chose. Des tâches autrefois gérables commencent à sembler impossibles, la motivation disparaît complètement, et même les petites décisions deviennent accablantes. Tu peux te sentir émotionnellement éteint·e ou inhabituellement au bord des larmes, tomber malade plus souvent, te retirer des gens autour de toi, et constater que tes symptômes TDAH – oublis, cécité temporelle, distractibilité – empirent nettement plus que d'habitude.`,
    `Ce qui rend le burnout TDAH si cruel, c'est la honte qui l'accompagne. Beaucoup lisent l'effondrement comme la preuve qu'ils sont paresseux ou défaillants, puis tentent de passer en force avec l'effort même qui l'a provoqué. Cette réaction ne fait que creuser le trou, car le burnout ne se résout pas en faisant plus d'efforts ; il se résout en faisant vraiment, et souvent inconfortablement, moins pendant un temps.`,
    `La récupération commence par la permission de te reposer sans l'avoir mérité. Abaisser la barre volontairement, lâcher chaque engagement non essentiel, externaliser les tâches pour que ton cerveau cesse de les porter, et demander du soutien ne sont pas des caprices ; ce sont le vrai traitement. Il aide aussi de regarder honnêtement ce qui a mené là, car le burnout est souvent le signe que ta vie demande à ta fonction exécutive plus qu'aucun cerveau ne peut donner durablement.`,
    `Guérir d'un burnout TDAH est rarement rapide, et cela arrive plutôt par vagues qu'en ligne droite. Sois patient·e et doux·ce avec toi-même, protège ton énergie comme si elle comptait – parce que c'est le cas –, et reconstruis tes routines lentement, avec bien plus de place pour le repos qu'il ne semble raisonnable. Le but n'est pas de revenir à rouler sur la réserve ; c'est de bâtir une vie qui cesse de vider le réservoir dès le départ.`,
  ],
  'how-to-clean-with-adhd': [
    `Si ton intérieur oscille entre impeccable et chaos total, avec très peu d'entre-deux, tu n'es ni paresseux·se ni négligent·e. Le ménage est vraiment plus difficile pour les cerveaux TDAH, parce qu'il repose précisément sur les compétences que le TDAH complique : démarrer, séquencer, soutenir l'attention et se sentir motivé·e par une tâche sans nouveauté et avec très peu de récompense tant qu'elle n'est pas complètement finie.`,
    `Une grande partie de la difficulté est la pensée tout-ou-rien. Beaucoup de personnes avec un TDAH ont l'impression que le ménage ne compte que si elles font toute la maison parfaitement, si bien que la tâche enfle jusqu'à devenir si énorme que le cerveau refuse de commencer. Le désordre grandit alors jusqu'à devenir une vraie crise, qui génère enfin assez d'urgence et d'adrénaline pour agir – un cycle épuisant et intenable.`,
    `La sortie consiste à rendre le premier pas presque risiblement petit. Au lieu de « nettoyer la cuisine », la tâche devient « dégager une section du plan de travail ». Régler un minuteur sur cinq ou dix minutes seulement fait des merveilles, car cela donne à ton cerveau un point d'arrivée clair et limité, et la pleine permission de t'arrêter quand il sonne. Le plus souvent, commencer est la partie la plus dure, et un peu d'élan te porte plus loin que prévu.`,
    `Emprunter un peu de dopamine rend le tout plus facile. Mettre une playlist préférée, un podcast captivant ou un livre audio transforme une tâche ennuyeuse en quelque chose de supportable, voire d'agréable. Le body doubling aide aussi : nettoyer aux côtés d'une amie, d'un partenaire ou même en appel vidéo te garde ancré·e, et te promettre une petite récompense précise à la fin donne à ton cerveau quelque chose de concret vers quoi avancer.`,
    `Il aide également de viser une remise à zéro plutôt qu'un grand ménage. Ton but, la plupart des jours, est simplement de rendre l'espace à nouveau fonctionnel, pas digne d'un magazine, et « assez bien » est une ligne d'arrivée tout à fait légitime. Garder le matériel de ménage visible et à portée de main, baisser volontairement tes exigences et t'attaquer à une pièce ou même à une seule surface à la fois réduisent tous la friction qui t'empêche de démarrer.`,
    `Le plus important : lâche le poids moral que tu as attaché à un intérieur rangé. Un espace en désordre n'est pas la preuve d'un caractère en désordre ; c'est simplement le signe que les conseils de ménage standards n'ont jamais été conçus pour la façon dont ton cerveau fonctionne. Avec de tout petits pas, un minuteur, un peu de dopamine et beaucoup moins de honte, un intérieur plus apaisé devient bien plus accessible – et un agenda doux qui découpe le travail en petits morceaux peut porter une part surprenante de cette charge pour toi.`,
  ],
}
for (const [slug, paras] of Object.entries(FR_BODY)) {
  articleBody[slug] = { ...(articleBody[slug] || {}), fr: paras }
}

const ES_BODY: Record<string, string[]> = {
  'why-adhd-brains-struggle-with-planning': [
    `Si tienes TDAH, planificar probablemente se siente como intentar retener agua en las manos. Empiezas con buenas intenciones — un planificador nuevo, un sistema fresco, un optimista lunes por la mañana — y de algún modo, para el martes ya se ha desmoronado todo. Eso no es un defecto de carácter. Es neurociencia.`,
    `El TDAH afecta al córtex prefrontal, la parte del cerebro responsable de las funciones ejecutivas: planificar, priorizar, gestionar el tiempo e iniciar tareas. Cuando ese sistema no funciona como en los cerebros neurotípicos, los métodos de planificación convencionales no solo no ayudan. Empeoran las cosas.`,
    `Los planificadores convencionales asumen que puedes mirar una lista y sentirte motivado·a para empezar. En los cerebros con TDAH la motivación no funciona así. Los cerebros con TDAH se activan por interés, urgencia, novedad y desafío, no por importancia o prioridad. Una tarea puede ser crucialmente importante y aun así sentirse imposible, mientras que una tarea completamente trivial pero interesante se termina de inmediato.`,
    `La ceguera temporal es otro factor clave. La mayoría de las personas tienen un reloj interno que les ayuda a sentir el paso del tiempo. Los cerebros con TDAH a menudo carecen de eso, lo que lleva a darse cuenta de repente de que han pasado horas, o de que una fecha límite es mañana cuando parecía estar a semanas de distancia.`,
    `¿Qué ayuda de verdad? Sistemas que trabajen con estos patrones en lugar de contra ellos. Planificación basada en la energía (asignar tareas según tu nivel de energía natural). Temporizadores visuales (representaciones visuales del tiempo que pasa). Body doubling (trabajar junto a otra persona). Y deshacer la espiral de vergüenza que surge cuando un sistema falla, porque precisamente esa vergüenza suele hacer que empezar sea aún más difícil.`,
    `El objetivo no es arreglar tu cerebro con TDAH. El objetivo es construir una vida que encaje con el cerebro que tienes.`,
  ],
  'dopamine-menu-guide': [
    `Si alguna vez te has encontrado incapaz de hacer nada útil, pero también sin poder relajarte de verdad, puede que conozcas esa zona gris peculiar del TDAH en la que estás demasiado agotado·a para trabajar pero demasiado inquieto·a para descansar. Un menú de dopamina está diseñado para ese momento: una lista elaborada con cuidado de actividades que reponen tu sistema de recompensa sin absorberte durante horas.`,
    `La idea parte de cómo funciona realmente la motivación con TDAH. Los cerebros con TDAH no carecen de motivación en general: carecen de dopamina suficiente para hacer que las tareas aburridas o sin recompensa imediata parezcan que valen el esfuerzo. Por eso puedes pasarte horas profundamente concentrado·a en algo que te apasiona y luego ser completamente incapaz de enviar un correo electrónico sencillo. El menú de dopamina funciona aprovechando eso: te da acceso rápido a pequeños incrementos de dopamina que hacen que tu cerebro vuelva a ponerse en marcha.`,
    `Construir el tuyo empieza por pensar en actividades en cuatro categorías de tamaño. Los aperitivos son cosas de uno a cinco minutos: saltar, una canción que te encanta, un dibujo rápido, hablar con alguien. Los platos principales son actividades de diez a treinta minutos que te absorben pero no te enganchan: un paseo, un podcast, cocinar algo sencillo. Los postres son placeres que te parecen bien merecidos: un episodio de una serie favorita, tiempo de videojuegos, leer por placer. Y las bebidas son microdosis de placer que puedes intercalar mientras trabajas: una buena bebida, música de fondo, luz agradable.`,
    `La clave es prepararlo de antemano. Cuando estás en la zona gris del TDAH, tu cerebro no puede generar opciones de forma fiable, y eso hace que la procrastinación por parálisis del scroll sea tan atractiva: es una toma de decisión mínima con estimulación de dopamina inmediata. Un menú preparado elimina esa brecha porque las opciones ya están ahí, filtradas para que no te absorban demasiado y no te enganchen en un agujero de estimulación del que es difícil salir.`,
    `Unas pocas reglas para que funcione. Mantén el menú donde realmente lo veas: en papel en tu escritorio, como fondo de pantalla del móvil, en una nota pegada en la pared. Revísalo cada pocas semanas, porque lo que funciona cambia. Y no lo uses como otra forma de productividad obligatoria: si algo del menú deja de sentirse bien, no está en la lista. El objetivo es placer genuino y regulación, no otra tarea que completar.`,
    `Los cerebros con TDAH necesitan estimulación para funcionar, y no hay nada de qué avergonzarse en diseñar deliberadamente tu entorno para conseguirla. Un menú de dopamina convierte esa necesidad de algo vergonzante y pasivo en algo que gestionas activamente, y para muchas personas es una de las herramientas más sencillas y transformadoras que encontrarán.`,
  ],
  'time-blindness-adhd': [
    `La ceguera temporal es una de las experiencias más desconcertantes del TDAH, y una de las más malentendidas. No es que no te importe la puntualidad. No es que no te esfuerces. Es que tu cerebro experimenta el tiempo de forma fundamentalmente diferente a como lo hacen los cerebros neurotípicos: en lugar de fluir de manera predecible y lineal, el tiempo con TDAH existe en su mayor parte como un estado binario. Hay ahora, y hay no ahora. Las fechas límite que están a días de distancia no se sienten reales hasta que de repente están encima.`,
    `La neurociencia que hay detrás es bastante clara. Los sistemas de dopamina y norepinefrina que regulan la atención también apoyan la percepción del tiempo. Cuando esos sistemas funcionan de manera diferente, como ocurre con el TDAH, la capacidad de sentir internamente el paso del tiempo se ve afectada. No es que te falte conciencia del tiempo como concepto. Es que no tienes acceso fiable a ese reloj interno que la mayoría de la gente da por sentado.`,
    `En el día a día, esto tiene efectos en cascada. Las transiciones son difíciles porque el tiempo que lleva pasar de una cosa a otra no se siente intuitivamente. Calcular cuándo salir de casa es un desafío, no porque no sepas cuánto tarda el trayecto en abstracto, sino porque no puedes sentir cuándo ha llegado el momento de parar lo que estás haciendo. Y la hiperfocalización agrava todo esto: cuando estás completamente absorbido·a por algo, horas pueden pasar sintiéndose como minutos, lo que hace que la gestión del tiempo sea todavía más impredecible.`,
    `Lo que más ayuda son las herramientas externas que hacen que el tiempo sea visible. Un temporizador Time Timer, que muestra el tiempo restante como un disco que desaparece, es extraordinariamente eficaz porque convierte el tiempo en algo visual. Poner alarmas para las transiciones, no solo para los eventos, ayuda a mantener el movimiento. Los calendarios de tiempo bloqueado que estiman cuánto lleva cada tarea hacen que las estimaciones sean explícitas en lugar de intuitivas. El objetivo es trasladar el seguimiento del tiempo desde tu interior, donde es poco fiable, hasta el entorno físico, donde puede ser consistente.`,
    `La vergüenza a menudo rodea la ceguera temporal porque parece, desde fuera, como desconsideración o falta de esfuerzo. Es útil nombrar esto abiertamente a las personas con las que trabajas o vives, porque cambiar el marco de "no le importa" a "su cerebro procesa el tiempo de otra manera" cambia completamente la conversación. Muchas personas con TDAH describen que entender la ceguera temporal fue un punto de inflexión, no porque resolviera el problema de inmediato, sino porque les permitió por fin dejar de interpretarlo como un defecto moral.`,
    `Con las herramientas adecuadas, la ceguera temporal se vuelve manejable. Los hábitos basados en el tiempo se construyen lentamente, los sistemas se ajustan a medida que aprendes qué funciona, y el objetivo no es convertirte en alguien que nunca llega tarde. Es construir suficientes andamiajes externos para que tu cerebro funcione bien con el tiempo que tienes.`,
  ],
  'habit-stacking-adhd': [
    `La mayoría de los consejos sobre creación de hábitos están diseñados para cerebros que no tienen TDAH, y se nota. El consejo estándar de hacer algo a la misma hora todos los días asume que tienes un sentido fiable del tiempo. Seguir una lista supone que recordarás consultarla. Y el mito de los 21 días asume una consistencia que los cerebros con TDAH rara vez pueden mantener sin importar cuánto se esfuercen.`,
    `El habit stacking funciona de forma diferente, y por eso funciona mejor con el TDAH. En lugar de anclar un hábito a una hora, lo anclas a otro comportamiento que ya ocurre de forma fiable. La lógica es que el hábito existente actúa como señal; cuando lo haces, también haces el nuevo. No tienes que recordarlo, no tienes que mirar el reloj: la cadena se activa sola.`,
    `La fórmula básica es sencilla: después de [hábito existente] haré [nuevo hábito]. Después de prepararme el café de la mañana, escribiré tres intenciones para el día. Después de sentarme en mi escritorio, haré un brain dump de dos minutos. Después de lavarme los dientes por la noche, anotaré la primera tarea de mañana en un post-it. Cada uno de estos pares conecta algo que ya ocurre con algo que quieres hacer, sin que haya que recordarlo activamente.`,
    `Espera irregularidad. El TDAH significa que tu capacidad varía enormemente de un día para otro. Los días malos, tu hábito puede parecerse a una versión de diez segundos. Aun así cuenta. La racha no es lo importante: la dirección sí.`,
    `¿Y si te saltas días? No es un fracaso. Es el TDAH. El hábito no se rompe porque hayas fallado días. Solo muere si decides que está muerto. Simplemente vuelve a empezar. Cada día es una nueva oportunidad de construir la vida de la que tu cerebro es capaz.`,
  ],
  'do-i-have-adhd-test': [
    `Si alguna vez te has sorprendido buscando "¿tengo TDAH?" a la una de la mañana, estás en buena compañía. Para muchos adultos, especialmente mujeres y personas que lo hacían bien en el colegio, la pregunta no surge hasta que la vida se complica lo suficiente como para que las estrategias de compensación dejen de funcionar. Un trabajo exigente, la crianza o simplemente gestionar la propia vida pueden hacer que patrones de siempre de repente sean imposibles de ignorar.`,
    `En los adultos, el TDAH rara vez se parece al cliché del niño hiperactivo rebotando por las paredes. Se parece a una persona brillante que no puede empezar el informe que vence mañana. Se parece a olvidar citas a pesar de tres recordatorios, tener cuarenta pestañas abiertas y cien más en la cabeza, y sentirse agotado·a por tareas que parecen no costar ningún esfuerzo a los demás. La lucha es real, y no es una cuestión de fuerza de voluntad.`,
    `Hay tres presentaciones. El tipo predominantemente inatento gira en torno a la atención, la memoria y la organización: el patrón de "perdido·a en mis pensamientos" que a menudo pasa completamente desapercibido. El tipo predominantemente hiperactivo-impulsivo gira en torno a la inquietud, la impulsividad y la intensidad emocional: el patrón de "siempre en marcha". El tipo combinado, el más frecuente, significa que experimentas rasgos significativos de ambos, y el equilibrio puede desplazarse según el estrés, el entorno y la tarea que tienes delante.`,
    `Algunas señales aparecen una y otra vez: dificultad para iniciar tareas incluso cuando realmente quieres hacerlas; ceguera temporal (los plazos se sienten lejanos y luego de repente llegan); perder cosas constantemente; hiperfocalizar en lo que te interesa mientras todo lo demás se desliza; y un sistema nervioso que reacciona más intensamente de lo que la situación parece requerir. Ninguna de estas señales por sí sola significa TDAH, pero un patrón consistente a lo largo de años merece atención.`,
    `Una autoevaluación no puede diagnosticarte, y no debería intentarlo. Lo que una buena evaluación sí puede hacer es ayudarte a poner palabras a patrones que has sentido durante años sin poder nombrarlos, y darte algo concreto que llevar a un profesional. Nuestro test de TDAH gratuito te guía a través de 40 preguntas basadas en los criterios del DSM-5 y te muestra hacia qué tipo apuntan tus respuestas, en unos cinco minutos, sin vergüenza y sin jerga.`,
    `Si los resultados resuenan contigo, el siguiente paso es hablar con un psiquiatra o psicólogo colegiado que pueda hacer una evaluación real y hablar sobre las opciones. Mientras tanto, sé amable contigo mismo·a. Entender cómo funciona tu cerebro no es encontrar algo que está mal en ti: es finalmente poder construir una vida que se adapte al cerebro que realmente tienes.`,
  ],
  'adhd-paralysis': [
    `La parálisis por TDAH es una de las facetas más frustrantes y menos comprendidas del TDAH. Es la experiencia de saber exactamente qué tienes que hacer, querer de verdad hacerlo, entender las consecuencias de no hacerlo, y aun así ser completamente incapaz de empezar. No eres perezoso·a. No lo estás evitando a propósito. Estás paralizado·a.`,
    `Hay varias variantes. La parálisis de tarea es la incapacidad de iniciar una sola tarea. La parálisis de elección aparece cuando hay demasiadas opciones y tu cerebro simplemente se niega a elegir una. Y la parálisis por sobrecarga ocurre cuando todo parece igualmente urgente, así que acabas sin hacer nada, a menudo con una culpa intensa. Las tres vienen del mismo lugar: un sistema ejecutivo momentáneamente desbordado.`,
    `La neurociencia ayuda a entender por qué "simplemente hazlo" nunca funciona. Iniciar una tarea requiere que tu cerebro estime el esfuerzo, ordene los pasos y genere suficiente dopamina para impulsar el movimiento. En los cerebros con TDAH, ese sistema de cebado es poco fiable. Cuando una tarea parece grande, aburrida o poco clara, el cerebro no logra movilizar la energía de activación, y cuanto más lo fuerzas, más se bloquea.`,
    `La salida casi nunca es esforzarse más. Es hacer el primer paso absurdamente pequeño. No "limpiar la cocina" sino "poner una taza en el fregadero". No "escribir el informe" sino "abrir el documento y escribir el título". El objetivo no es terminar: es romper el bloqueo. El movimiento genera dopamina, y la dopamina hace posible el siguiente paso. Por eso el impulso se siente tan bien una vez que empieza.`,
    `Lo que también ayuda de verdad: el body doubling, donde trabajas junto a otra persona (aunque sea por videollamada) para que tu cerebro tome prestada su concentración. Externalizar los pasos, para que vivan en el papel en lugar de girar en tu cabeza. Poner un temporizador de solo cinco minutos, con el permiso total de parar cuando suene. Y un brain dump para despejar el desorden mental antes de elegir qué importa. Cada uno de estos reduce la energía de activación que la tarea exige.`,
    `Sobre todo, suelta la vergüenza. La parálisis es un síntoma, no un defecto de carácter, y la vergüenza es combustible para el bloqueo: hace que la tarea sea aún más amenazante, lo que bloquea tu cerebro con más fuerza. Lo más amable y eficaz que puedes hacer es tratar un momento de bloqueo como información, reducir el paso y darte permiso para empezar mal. Empezar mal sigue contando como empezar.`,
  ],
  'best-planner-for-adhd': [
    `Si has comprado una agenda bonita, la has usado religiosamente durante nueve días y luego la has visto convertirse en un caro pisapapeles, el problema no era la agenda ni eras tú. La mayoría de las agendas están diseñadas para cerebros neurotípicos: asumen que pensarás en abrirlas, que una lista ordenada te motivará y que experimentas el tiempo como un flujo regular y predecible. Los cerebros con TDAH no funcionan así, por lo que la herramienta te prepara discretamente para el fracaso.`,
    `Una agenda apta para el TDAH necesita hacer algo diferente. Tiene que externalizar el tiempo, porque los cerebros con TDAH lo sienten mal pasar. Tiene que hacer que empezar sea fácil, porque la iniciación de tareas es la parte más difícil. Y tiene que ser indulgente, porque un sistema que te castiga por un día perdido será abandonado en cuanto te atases, lo cual con TDAH es inevitable y completamente normal.`,
    `Lo primero que hay que buscar es una descomposición de tareas integrada. "Organizar un evento" es paralizante; "escribir al local, elegir tres fechas, redactar la invitación" es factible. Una agenda que te deje espacio para dividir las tareas en pequeños pasos concretos elimina el mayor obstáculo de los cerebros con TDAH. Si la agenda solo te da una línea de to-do en blanco, está pidiéndole a tu función ejecutiva el trabajo que menos puede hacer.`,
    `Lo segundo es una estructura basada en la energía en lugar de un horario rígido por horas. La energía con TDAH fluctúa enormemente, y una agenda que asume que harás trabajo profundo a las 9 en punto cada día estará equivocada la mayoría de las veces. Planificar en torno a tus ventanas de energía natural, las tareas exigentes en los momentos de alta energía, lo administrativo en los de baja energía, trabaja con tu cerebro en lugar de contra él.`,
    `Lo tercero, y el más ignorado, es la amabilidad integrada. Las mejores agendas para TDAH hacen espacio para los brain dumps, para los días de "suficientemente bien", para celebrar las pequeñas victorias y para volver a empezar sin culpa. Tratan un día perdido como una página en blanco, no como una racha rota. Eso no es sentimentalismo: es estratégico, porque la vergüenza es una de las principales razones por las que los sistemas para TDAH se derrumban.`,
    `Es exactamente en torno a esto que está construida la caja de herramientas de bloom focus: agendas que descomponen las tareas por ti, estructura organizada en torno a la energía en lugar de relojes rígidos, y un tono que nunca te hace sentir que vas retrasado·a. Si te has culpado de cada agenda abandonada, puede que haya sido el diseño el que te ha fallado, no tu disciplina. La herramienta adecuada se siente menos como un examen que suspendes repetidamente y más como una mano apoyada en tu espalda.`,
  ],
  'adhd-in-women': [
    `Durante décadas, el TDAH se estudió casi exclusivamente en niños pequeños, los hiperactivos que no podían quedarse quietos en clase. El resultado es un cuadro diagnóstico que no capta cómo se manifiesta el TDAH más a menudo en mujeres y niñas, que es la razón por la que tantas mujeres no reciben un diagnóstico hasta los treinta, los cuarenta o más, a menudo después de que evalúen a su propio hijo, cuando los síntomas de repente les resultan familiares.`,
    `En las mujeres, el TDAH es más frecuentemente inatento que hiperactivo, y el TDAH inatento es silencioso. No altera la clase. Se parece a soñar despierta, a ser "cabeza en las nubes" o "despistada", a una chica lista que no alcanza su potencial. Porque no molesta a nadie más, pasa desapercibido, y la chica aprende a enmascararlo, a menudo a un enorme coste interno.`,
    `Ese enmascaramiento es una parte enorme de la historia. Muchas mujeres con TDAH se convierten en perfeccionistas intensas y sobrepreparadoras, construyendo elaborados sistemas para compensar un cerebro que no comprenden. Por fuera, parecen organizadas y competentes. Por dentro, están agotadas, ansiosas y convencidas de que un descuido bastante bastaría para que todo el mundo descubriera lo mucho que trabajan para seguir el ritmo.`,
    `Por eso el TDAH en mujeres se diagnostica erróneamente tan a menudo como ansiedad o depresión. Esas condiciones pueden perfectamente coexistir, pero la ansiedad es frecuentemente la consecuencia de años de TDAH no diagnosticado: el estrés crónico de los plazos perdidos, la vergüenza de los olvidos, el coste de trabajar el doble de duro para el mismo resultado. Tratar la ansiedad sin reconocer el TDAH que hay debajo solo aborda la mitad del cuadro.`,
    `Las hormonas añaden una capa que la investigación antigua ignoraba por completo. El estrógeno influye en la dopamina, por lo que los síntomas del TDAH a menudo se intensifican antes de la menstruación, después del parto y durante la perimenopausia. Muchas mujeres describen síntomas que de repente se vuelven inmanejables en torno a los cuarenta, no porque algo vaya mal, sino porque un cambio hormonal ha eliminado el amortiguador en el que se habían apoyado inconscientemente durante años.`,
    `Si algo de todo esto suena como tu propio diario, no estás rota, no eres dramática y no te lo estás inventando. Puede que simplemente tengas un cerebro que nunca ha sido evaluado según sus propios términos. Una autoevaluación puede ayudarte a nombrar el patrón, y un profesional colegiado puede darte una evaluación real. Entenderlo lo cambia todo, no porque te conviertas en otra persona, sino porque finalmente puedes dejar de culparte por serlo.`,
  ],
  'adhd-rejection-sensitive-dysphoria': [
    `La disforia sensible al rechazo, o RSD, es el dolor emocional intenso que sigue a un rechazo, una crítica o un fracaso, reales o percibidos. Para muchas personas con TDAH, es el síntoma más perturbador de todos, y sin embargo casi nadie es advertido de ello en el momento del diagnóstico. Un comentario de pasada de un compañero, un mensaje que se queda sin respuesta, o un pequeño error en el trabajo pueden cada uno desencadenar una oleada de dolor tan fuerte que se vuelve física y completamente desproporcionada con lo que realmente ha ocurrido.`,
    `La razón es neurológica, no una cuestión de sensibilidad excesiva. Los cerebros con TDAH regulan las emociones de manera diferente, y los sentimientos llegan más rápido, más fuerte y son más difíciles de apagar. Los mismos sistemas de dopamina y norepinefrina que dificultan la concentración también hacen más difícil reducir la intensidad emocional; donde una persona neurotípica sentiría un pequeño pinchazo, un cerebro con TDAH puede experimentar, en segundos, algo más cercano a una devastación real.`,
    `La RSD tiene muchos disfraces. A veces parece complacer a los demás, donde dices que sí a todo para que nadie nunca se decepcione de ti. A veces parece perfeccionismo, o la silenciosa negativa a intentar cosas en las que podrías fallar. A veces se vuelca hacia fuera en ira o defensividad repentinas. Y muy a menudo parece retirada: cancelar planes, evitar el feedback, o alejarte de la gente en cuanto sientes que podrías ser juzgado·a.`,
    `Porque el dolor es invisible, a las personas que viven la RSD a menudo se les dice que exageran o que son dramáticas. Esta reacción lo empeora todo, porque apila vergüenza sobre un sentimiento ya abrumador. Entender que la RSD es un patrón reconocido dentro del TDAH, y no un defecto de carácter, suele ser lo más aliviador que una persona puede aprender, porque finalmente explica toda una vida de reacciones que nunca parecieron tener sentido.`,
    `Lo que ayuda es una mezcla de nombrar y ganar distancia. Aprender a reconocer el momento como "esto es la RSD, no la verdad" crea un pequeño espacio entre el sentimiento y tu reacción. Esperar antes de responder a un mensaje detonante, cotejar tu interpretación con los hechos reales y preparar frases amables para recibir feedback reducen todos la intensidad. Hablar abiertamente con personas de confianza también ayuda: pueden recordarte que un comentario no es un veredicto sobre tu valía.`,
    `Sobre todo, la RSD responde a la autocompasión más que a la autocrítica. El sentimiento es real y es doloroso, pero también es temporal, y pasa más rápido cuando lo recibes con amabilidad en lugar de combatirlo. No eres "demasiado·a", y no estás roto·a. Simplemente tienes un cerebro que siente las cosas a todo volumen, y esa misma intensidad, dirigida a otro lugar, es a menudo también de donde vienen tu calidez y tu creatividad.`,
  ],
  'adhd-and-sleep': [
    `Si tu cerebro se despierta en el momento en que tu cabeza toca la almohada, estás lejos de ser el único·a. Los problemas de sueño son una de las facetas más frecuentes y menos mencionadas del TDAH, y afectan a una gran mayoría de adultos con este diagnóstico. El patrón es dolorosamente familiar: agotado·a todo el día, y luego de repente muy despierto·a por la noche, con una mente que corre entre conversaciones, ideas, preocupaciones y la lista de cosas pendientes de mañana, justo cuando más necesitas que se calle.`,
    `Una parte de ello es puramente biológica. Muchas personas con TDAH tienen un ritmo circadiano retrasado, lo que significa que su señal natural de sueño llega unas horas más tarde de lo que el resto del mundo espera. A eso se suma que el cerebro con TDAH está infraestimulado cuando no hay nada que hacer, de modo que el silencio de la hora de acostarse puede sentirse intolerable en lugar de reparador, y la mente sale en busca de estimulación en forma de pensamientos acelerados o un episodio más.`,
    `Aquí entra el famoso segundo aire. Justo cuando tu cuerpo finalmente está listo para desacelerarse, aparece un impulso de energía o concentración, y de repente estás limpiando a fondo la cocina a medianoche o lanzando un proyecto. Los investigadores a veces llaman a este patrón más amplio procrastinación vengativa de la hora de acostarse: cuando el día no te ha dejado ningún tiempo que se sienta tuyo, la noche tardía se convierte en la única ventana de libertad, y el sueño pierde en silencio.`,
    `Las mañanas pagan entonces el precio. Los cerebros con TDAH a menudo experimentan una inercia del sueño intensa, ese estado pesado y nebuloso que hace que levantarse sea casi imposible, sin importar cuántas alarmas se pongan. No es pereza y no es un fallo moral. Es el resultado predecible de un cerebro que se quedó dormido demasiado tarde y ahora tiene que despertarse según un horario diseñado para el reloj interno de otra persona.`,
    `Lo que ayuda es suave y regular en lugar de estricto. Una rutina de calma que empiece antes de lo que parece necesario, un brain dump en papel para vaciar los pensamientos acelerados antes de acostarse, luz más tenue por la noche y más brillante por la mañana, y una hora de despertar que se mantenga más o menos igual incluso el fin de semana van empujando poco a poco el ritmo a su lugar. Externalizar las tareas de mañana para que tu cerebro confíe en que están bien anotadas suele marcar la diferencia entre quedarse despierto·a y soltar.`,
    `Ten paciencia contigo mientras experimentas, porque el sueño rara vez se repara en una sola noche. El objetivo no es una higiene del sueño perfecta, como en los manuales: es un puñado de pequeños hábitos repetibles que hagan que dormirse sea un poco más fácil y las mañanas un poco más amables. Trabajar con tu reloj interno en lugar de contra él es mucho más sostenible que forzar un horario que nunca estuvo hecho para un cerebro con TDAH.`,
  ],
  'body-doubling-adhd': [
    `¿Alguna vez has notado lo mucho más fácil que es avanzar cuando simplemente hay alguien más en la habitación? Esa es toda la idea del body doubling, una de las estrategias de concentración más fiables para los cerebros con TDAH. Un body double es una persona que trabaja junto a ti, sin ayudar en tu tarea, solo presente, y su tranquila compañía hace que la tarea imposible de repente sea realizable.`,
    `Funciona porque el TDAH es, en el fondo, un desafío de autorregulación más que de conocimiento. Generalmente sabes exactamente qué hacer; lo difícil es empezar y mantenerse. Tener a otra persona allí aporta una suave responsabilidad externa y una sensación de concentración prestada, y añade justo la suficiente novedad y leve presencia social para darle a tu cerebro el impulso de dopamina que necesita para arrancar y continuar.`,
    `El body doubling existe en muchas formas, así que puedes elegir lo que encaje en tu vida. Puede ser una amiga que lee en el sofá mientras tú ordenas papeles, una pareja que cocina mientras tú recoges, o una videollamada donde dos personas trabajan en silencio en cosas completamente separadas. También hay plataformas de coworking virtual dedicadas y aplicaciones de concentración adaptadas al TDAH donde te unes a una sesión con desconocidos y simplemente trabajas en paralelo.`,
    `La puesta en marcha es sorprendentemente sencilla. Decide en qué vas a trabajar, dile a tu body double en qué empiezas, poneos de acuerdo sobre una duración y luego empezad juntos. Un pequeño balance al final, donde cada uno nombra lo que ha terminado, cierra el círculo y ofrece una pequeña dosis de satisfacción. Lo esencial es que nadie te vigila ni te juzga: la magia reside únicamente en la presencia compartida.`,
    `El body doubling brilla precisamente en las tareas que los cerebros con TDAH más evitan: el papeleo aburrido, la limpieza, las pilas de correos, rellenar formularios, y todo lo que lleva semanas sin tocarse. Se trata menos de las habilidades de la otra persona que de romper el hechizo de la evitación: por eso incluso un compañero casi silencioso que no sabe nada de tu trabajo puede transformar completamente lo que logras hacer.`,
    `Si siempre has trabajado mejor en una cafetería animada o te has sentido extrañamente productivo·a cuando una amiga estaba cerca, el body doubling simplemente convierte ese instinto en una herramienta a la que puedes recurrir deliberadamente. No es una muleta y no es hacer trampa. Es una adaptación inteligente que trabaja con el cableado de tu cerebro, y muchos lo encuentran una de sus formas más fiables de empezar.`,
  ],
  'adhd-burnout': [
    `El burnout por TDAH no es lo mismo que el cansancio ordinario, ni lo mismo que el estrés cotidiano. Es el agotamiento profundo, de todo el cuerpo, que llega después de meses o años de empujar un cerebro a funcionar de maneras para las que nunca fue construido. A menudo sigue a un largo período de enmascaramiento, sobrecompensación y aguantar el día a día apretando los dientes, hasta que un día los sistemas que apenas aguantaban finalmente ceden todos a la vez.`,
    `Los cerebros con TDAH son especialmente vulnerables a esto porque hay un enorme esfuerzo invisible en parecer que todo va bien. Recordar, planificar, contener impulsos, gestionar emociones y cumplir las expectativas neurotípicas consumen toda una energía ejecutiva que ya de por sí escasea. Vivir en un estado constante de ponerse al día crea una especie de descubierto ejecutivo crónico, y en algún momento la factura llega en forma de burnout.`,
    `Las señales se confunden fácilmente con otras cosas. Las tareas que antes eran manejables empiezan a parecer imposibles, la motivación desaparece por completo, y hasta las pequeñas decisiones se vuelven abrumadoras. Puedes sentirte emocionalmente apagado·a o inusualmente al borde de las lágrimas, enfermar más a menudo, retirarte de las personas a tu alrededor, y notar que tus síntomas de TDAH, olvidos, ceguera temporal, distractibilidad, empeoran notablemente más de lo habitual.`,
    `Lo que hace tan cruel al burnout por TDAH es la vergüenza que lo acompaña. Muchos interpretan el colapso como prueba de que son perezosos o que están fallando, y luego intentan abrirse paso a la fuerza con el mismo esfuerzo que lo provocó. Esa reacción solo profundiza el agujero, porque el burnout no se resuelve esforzándose más: se resuelve haciendo genuinamente, y a menudo incómodamente, menos durante un tiempo.`,
    `La recuperación empieza por el permiso de descansar sin haberlo merecido. Bajar la barra voluntariamente, soltar cada compromiso no esencial, externalizar las tareas para que tu cerebro deje de cargarlas, y pedir apoyo no son caprichos: son el tratamiento real. También ayuda mirar honestamente qué llevó hasta aquí, porque el burnout es a menudo la señal de que tu vida le exige a tu función ejecutiva más de lo que ningún cerebro puede dar de forma sostenida.`,
    `Recuperarse de un burnout por TDAH rara vez es rápido, y llega más bien en oleadas que en línea recta. Ten paciencia y sé amable contigo, protege tu energía como si importara, porque importa, y reconstruye tus rutinas lentamente, con mucho más espacio para el descanso del que parece razonable. El objetivo no es volver a funcionar al límite: es construir una vida que no vacíe el depósito desde el principio.`,
  ],
  'how-to-clean-with-adhd': [
    `Si tu casa oscila entre impecable y caos total, con muy poco término medio, no eres perezoso·a ni descuidado·a. Limpiar es realmente más difícil para los cerebros con TDAH, porque se apoya precisamente en las habilidades que el TDAH complica: empezar, secuenciar, mantener la atención y sentirse motivado·a por una tarea sin novedad y con muy poca recompensa hasta que no está completamente terminada.`,
    `Gran parte de la dificultad es el pensamiento de todo o nada. Muchas personas con TDAH sienten que limpiar solo cuenta si hacen toda la casa a la perfección, de modo que la tarea se hincha hasta volverse tan enorme que el cerebro se niega a empezar. El desorden crece entonces hasta convertirse en una verdadera crisis, que finalmente genera suficiente urgencia y adrenalina para actuar, en un ciclo agotador e insostenible.`,
    `La salida es hacer el primer paso casi ridículamente pequeño. En lugar de "limpiar la cocina", la tarea se convierte en "despejar una sección de la encimera". Poner un temporizador en solo cinco o diez minutos hace maravillas, porque le da a tu cerebro un punto final claro y limitado, y el pleno permiso de parar cuando suene. La mayoría de las veces, empezar es la parte más difícil, y un poco de impulso te lleva más lejos de lo que esperabas.`,
    `Tomar prestada algo de dopamina lo hace todo más fácil. Poner una playlist favorita, un podcast cautivador o un audiolibro convierte una tarea aburrida en algo tolerable, incluso agradable. El body doubling también ayuda: limpiar junto a una amiga, una pareja o incluso por videollamada te mantiene anclado·a, y prometerte una pequeña recompensa concreta al final le da a tu cerebro algo tangible hacia lo que avanzar.`,
    `También ayuda apuntar a un reinicio en lugar de a una limpieza a fondo. Tu objetivo la mayoría de los días es simplemente hacer el espacio funcional de nuevo, no digno de una revista, y "suficientemente bien" es una línea de llegada completamente legítima. Mantener los utensilios de limpieza visibles y a mano, bajar deliberadamente tus expectativas y atacar una habitación, o incluso una sola superficie, a la vez reduce toda la fricción que te impide empezar.`,
    `Lo más importante: suelta el peso moral que has atado a un hogar ordenado. Un espacio desordenado no es prueba de un carácter desordenado: es simplemente la señal de que los consejos de limpieza estándar nunca fueron diseñados para la forma en que funciona tu cerebro. Con pasos diminutos, un temporizador, un poco de dopamina y mucha menos vergüenza, un hogar más tranquilo se vuelve mucho más alcanzable, y una agenda amable que divide el trabajo en pequeños trozos puede cargar una parte sorprendente de ese peso por ti.`,
  ],
}
for (const [slug, paras] of Object.entries(ES_BODY)) {
  articleBody[slug] = { ...(articleBody[slug] || {}), es: paras }
}

const NEW5_DE: Record<string, string[]> = {
  'adhd-emotional-dysregulation': [
    `Wenn du ADHS hast, wurdest du wahrscheinlich irgendwann als zu empfindlich, zu intensiv oder überreagierend bezeichnet. Was die meisten Menschen – und viele Kliniker – nicht erkennen, ist, dass emotionale Dysregulation kein Charakterzug ist, der dem ADHS aufgesetzt ist. Sie ist eines seiner zentralsten und am wenigsten diskutierten Merkmale. Das ADHS-Gehirn kämpft nicht nur mit Aufmerksamkeit und Impulskontrolle. Es kämpft damit, Größe und Dauer emotionaler Reaktionen zu regulieren, was bedeutet, dass Gefühle schneller ankommen, härter treffen und länger anhalten als bei den meisten Menschen.`,
    `Die Neurowissenschaft hilft zu erklären, warum. Der präfrontale Kortex – der Teil des Gehirns, der dafür zuständig ist, emotionale Reaktionen zu moderieren, vor dem Reagieren innezuhalten und Gefühle in einen Kontext zu setzen – ist derselbe Bereich, der bei ADHS am stärksten betroffen ist. Wenn dieses System zu schwach arbeitet, feuern die emotionalen Zentren des Gehirns, insbesondere die Amygdala, ohne ausreichendes Bremsen. Das Ergebnis ist nicht, dass ADHS-Gehirne mehr fühlen als andere. Es ist, dass sie fühlen, ohne den üblichen Puffer zwischen Fühlen und Reagieren.`,
    `Das zeigt sich in einigen erkennbaren Mustern. Frustration kann sich in Sekunden zu Wut steigern, über etwas, das von außen geringfügig wirkt. Aufregung kann in impulsive Entscheidungen oder zerstreutes Denken umschlagen. Enttäuschung kann in stundenlange Niedergeschlagenheit gleiten, die sich wie Depression anfühlt, sich aber unerwartet hebt. Und Übergänge – von einem emotionalen Zustand, einer Aufgabe oder Umgebung zur anderen – können wirklich destabilisierend sein, weil das Nervensystem das Letzte noch nicht verarbeitet hat.`,
    `Was das besonders schmerzhaft macht, ist die Diskrepanz zwischen innerer Erfahrung und äußerer Wahrnehmung. Die Person mit ADHS weiß, dass das Gefühl intensiv ist; sie weiß auch meistens intellektuell, dass die Reaktion unverhältnismäßig sein könnte. Aber das Wissen hilft im Moment nicht, weil das Bremssystem genau das ist, was nicht funktioniert. Die Scham, die folgt – für das Ausrasten, das Weinen, das impulsive Reden – verstärkt oft die ursprüngliche Schwierigkeit und wird zur eigenen Dysregulationsquelle.`,
    `Was wirklich hilft, ist eine Lücke zwischen Reiz und Reaktion zu schaffen – nicht durch Willenskraft, die zu langsam ist, sondern durch körperliche und umgebungsbezogene Strategien. Das Emotion laut zu benennen schafft eine winzige Pause. Die Situation zu verlassen, bevor es eskaliert statt danach, gibt dem Nervensystem Zeit zum Zurücksetzen. Kaltes Wasser, Bewegung oder langsames Atmen können den physiologischen Zustand direkt verschieben. Und die Arbeit mit einem Therapeuten an Emotionserkennung und Reaktionsmustern hilft mittelfristig, nicht durch Unterdrücken von Gefühlen, sondern durch ihr Lesbarmachen in Echtzeit.`,
    `Vor allem verändert das Verständnis, dass emotionale Dysregulation neurologisch und nicht moralisch ist, das gesamte Bild. Du bist nicht zu viel. Du bist nicht schwach. Du hast ein Gehirn, das Dinge in voller Lautstärke fühlt, und dieselbe Intensität ist, wenn sie nicht unter Druck steht, oft die Quelle deiner Empathie, Kreativität und tiefen Fürsorge. Das Ziel ist nicht, weniger zu fühlen. Es ist, genug Unterstützung um diese Gefühle herum zu bauen, damit sie aufhören, das Auto zu fahren.`,
  ],
  'adhd-hyperfocus': [
    `Eine der verwirrenden Seiten von ADHS ist, dass es nicht wie ein Aufmerksamkeitsdefizit aussieht, wenn du vier Stunden tief in etwas versunken bist, das du liebst, und dabei völlig vergessen hast zu essen, zu trinken oder zu bemerken, dass es draußen dunkel wurde. Das ist Hyperfokus: die intensive, unfreiwillige Absorption in einer Aufgabe oder einem Thema, die ADHS von außen wie das Gegenteil seiner selbst aussehen lassen kann. Und er ist genauso ein Symptom wie die Ablenkbarkeit – nur eben das Symptom, vor dem niemand dich warnt.`,
    `Hyperfokus entsteht, weil das ADHS-Gehirn nicht wirklich wenig Aufmerksamkeit hat. Es hat Schwierigkeiten zu regulieren, wohin die Aufmerksamkeit geht. In neurotypischen Gehirnen wird Aufmerksamkeit durch Priorität und Absicht gesteuert. In ADHS-Gehirnen wird sie hauptsächlich durch Interesse und Stimulation gesteuert. Wenn etwas dieses Interesse wirklich erfasst – ein kreatives Projekt, ein Videospiel, eine Recherchespirale, eine neue Obsession – flutet das Gehirn mit Dopamin und rastet ein. Die Außenwelt hört auf, wahrgenommen zu werden. Die Zeit verschwindet. Alles, was nicht die Sache ist, wird unsichtbar.`,
    `Das klingt wie eine Superkraft, und manchmal ist es das. Hyperfokus kann außerordentliche Leistungen, tiefes Fachwissen und jene Art kreativer Absorption hervorbringen, die wirklich gute Arbeit erzeugt. Aber er hat auch eine Schattenseite. Du kannst ihn nicht zuverlässig für die wichtigsten Dinge abrufen. Du kannst dich in etwas Unwichtigem vollständig verlieren, während entscheidende Fristen verstreichen. Übergänge aus dem Hyperfokus heraus sind oft brutal – das Gehirn widersteht dem Zurückziehen, was wie emotionaler Widerstand oder Zusammenbruch aussehen kann. Und der Absturz danach, wenn der Dopaminspiegel sinkt, kann sich wie eine leichte Depression anfühlen.`,
    `Hyperfokus ist auch nicht dasselbe wie Flow, obwohl sie sich ähnlich anfühlen. Flow ist ein Zustand, den man mit dem richtigen Herausforderungsniveau absichtlich betreten kann. Hyperfokus ist eher unfreiwillig, schwerer zu verlassen und nicht immer mit etwas verbunden, was die Person tatsächlich priorisieren möchte. Diese Unterscheidung ist wichtig, weil Flow-Strategien sich nicht immer auf Hyperfokus-Management übertragen lassen.`,
    `Mit dem Hyperfokus zu arbeiten statt gegen ihn bedeutet in der Praxis einige Dinge. Ein Wecker zu stellen, bevor man mit etwas Absorbierendem beginnt, gibt dem Gehirn ein Austrittssignal, das es nicht selbst erstellt hat und daher wahrnehmen muss. Hoch-interessante Aufgaben für Zeiten aufzubewahren, in denen man es sich leisten kann, sich darin zu verlieren – Abende, freie Blöcke – schützt den Rest des Zeitplans. Und ein kurzes Übergangsritual einzubauen, wenn man aufhören muss – ein fünfminütiges Herunterfahren, eine kurze Notiz darüber, wo man steht, eine kurze Bewegungspause – hilft dem Nervensystem, die Gänge zu wechseln, statt sie zu mahlen.`,
    `Das Verständnis von Hyperfokus hilft auch beim Selbsturteil. Dasselbe Gehirn, das die Steuererklärung nicht beginnen kann, kann sechs Stunden ohne Pause schreiben. Das ist keine Inkonsistenz. Das ist das ADHS-Aufmerksamkeitssystem, das genau das tut, was es tut: Interesse verfolgen, nicht Wichtigkeit. Das Ziel ist nicht, Hyperfokus loszuwerden, sondern genug Gerüst darum herum zu bauen, dass er zu einem Asset wird, den man größtenteils steuern kann, statt zu einer Kraft, die einem einfach passiert.`,
  ],
  'adhd-executive-dysfunction': [
    `Exekutive Dysfunktion ist einer jener Begriffe, der klinisch und abstrakt klingt, bis man ihn erlebt – und dann klingt er genau richtig. Es ist die Erfahrung, genau zu wissen, was man tun muss, die Fähigkeit zu haben, es zu tun, es zu wollen – und festzustellen, dass der Teil des Gehirns, der dafür zuständig ist, den Anfang zu machen, schlicht nicht kooperiert. Das ist keine Faulheit. Das ist kein schlechter Charakter. Das ist eine spezifische neurologische Schwierigkeit mit den Fähigkeiten, die Menschen erlauben, zielgerichtetes Verhalten zu planen, zu beginnen, zu sequenzieren, zu überwachen und abzuschließen.`,
    `Diese Fähigkeiten sitzen hauptsächlich im präfrontalen Kortex, dem Kommandozentrum des Gehirns für die Organisation von Denken und Handeln. In ADHS-Gehirnen entwickelt sich dieses System langsamer und funktioniert anders – nicht in jedem Kontext und nicht jeden Tag gleich, aber genug, dass Aufgaben, die anhaltende Selbststeuerung erfordern, konsequent schwerer sind als sie sein sollten. Die Schwierigkeit liegt nicht bei Intelligenz, Verständnis oder sogar Motivation im Abstrakten. Sie liegt in dem neurologischen Apparat, der Absicht in Handlung übersetzt.`,
    `Exekutive Dysfunktion zeigt sich bei Menschen und Situationen unterschiedlich. Für manche ist es das Beginnen von Aufgaben – die benötigte Aktivierungsenergie fühlt sich unmöglich hoch an, besonders für Aufgaben, die langweilig, unklar oder ohne unmittelbare Belohnung sind. Für andere ist es das Wechseln zwischen Aufgaben – Übergänge fühlen sich mühsam an, und das Gehirn widersteht dem Loslassen von dem, was es gerade macht. Für wieder andere ist es das Arbeitsgedächtnis – die Fähigkeit, Informationen im Kopf zu halten, während man sie verwendet – sodass Anweisungen verloren gehen, Schritte übersprungen werden und komplexe mehrteilige Aufgaben zu einer Wand werden.`,
    `Die Inkonsistenz ist einer der schmerzhaftesten und am wenigsten verstandenen Aspekte. Exekutive Funktion bei ADHS ist nicht gleichmäßig beeinträchtigt. Wenn etwas wirklich interessant, dringend, neu oder emotional aufgeladen ist, kann das Gehirn exekutive Funktion produzieren, die völlig typisch aussieht. Deshalb wird ADHS oft nicht erkannt, und deshalb internalisieren Menschen mit ADHS oft die Schlussfolgerung, dass sie die Sache immer tun könnten, wenn sie sich genug anstrengen würden. Die Wahrheit ist, dass dasselbe Gehirn, das brillant um Mitternacht unter einer Deadline schreibt, dasselbe Stück nicht zuverlässig um 10 Uhr morgens schreiben kann, wenn es alle Zeit der Welt hat. Kontext tut viel von der Arbeit, die exekutive Funktion normalerweise macht.`,
    `Mit exekutiver Dysfunktion zu arbeiten bedeutet, so viel wie möglich zu externalisieren. Schriftliche Aufgabenlisten, Timer, visuelle Zeitpläne und physische Erinnerungen machen alle die Arbeit des Haltens von Struktur, die das Gehirn nicht zuverlässig intern tut. Aufgaben in die kleinstmöglichen Schritte zu unterteilen, beseitigt die Planungslast vom Moment des Anfangens. Body Doubling, Musik oder Umgebungshinweise zu nutzen, um dem Gehirn zu signalisieren, dass es Zeit zum Arbeiten ist, leiht Struktur von außen, wenn die Innenseite sie nicht erzeugt. Das sind keine Umgehungen für ein Defizit – das ist, wie das Gehirn tatsächlich am besten funktioniert.`,
    `Das wichtigste Umdeuten ist, dass exekutive Dysfunktion kein Maß für dein Potenzial, deine Intelligenz oder deinen Wert ist. Manche der fähigsten, kreativsten und engagiertesten Menschen der Welt haben erhebliche exekutive Dysfunktion. Was sie gemeinsam haben, ist nicht, dass sie sie durch Willenskraft überwunden haben, sondern dass sie Umgebungen und Systeme aufgebaut haben, die mit dem Gehirn funktionierten, das sie haben. Das ist das eigentliche Ziel: nicht härter, sondern klüger – das Leben so strukturieren, dass das Gehirn das tun kann, was es am besten kann.`,
  ],
  'adhd-and-anxiety': [
    `ADHS und Angst kommen so häufig zusammen vor, dass Forscher Jahrzehnte damit verbracht haben, zu entwirren, was zuerst kommt, ob sie eine gemeinsame Wurzel haben oder ob das eine einfach das andere verursacht. Die ehrliche Antwort ist: Es ist kompliziert, und es variiert wahrscheinlich von Person zu Person. Was klar ist, ist, dass beides zusammenzuhaben nicht ungewöhnlich ist – Schätzungen zufolge erfüllen etwa die Hälfte der Erwachsenen mit ADHS auch die Kriterien für eine Angststörung – und dass die Behandlung des einen, ohne das andere zu erkennen, eine erhebliche Lücke hinterlässt.`,
    `Ein Teil der Verbindung ist neurologisch. Sowohl ADHS als auch Angst beinhalten Dysregulation in den Dopamin- und Noradrenalinsystemen, die Aufmerksamkeit, emotionale Reaktion und Bedrohungserkennung steuern. ADHS-Gehirne neigen dazu, auf niedrigstufige Stimulation zu unterre­agieren und Neuheit zu suchen; ängstliche Gehirne neigen dazu, auf Bedrohungshinweise zu über­reagieren und Risiken zu katastrophisieren. Wenn diese beiden Systeme in derselben Person gestört sind, kann das Ergebnis ein Gehirn sein, das gleichzeitig zu Stimulation hingezogen wird und die Konsequenzen fürchtet – ein Muster, das einen besonderen Typ von erschöpfendem innerem Konflikt erzeugt.`,
    `Ein Teil der Verbindung ist auch erfahrungsbasiert. Jahre mit verpassten Deadlines, vergessenen Verpflichtungen, impulsiven Entscheidungen und sozialen Fehlern schaffen eine sehr rationale Grundlage für Angst. Wenn man gelernt hat, dass das eigene Gehirn unberechenbar ist, dass wichtige Dinge ohne Vorwarnung durch die Ritzen fallen können und dass andere Menschen oft von dem eigenen Verhalten verwirrt oder frustriert sind, beginnt Wachsamkeit wie die einzig vernünftige Reaktion zu erscheinen. Die Angst ist in diesem Fall kein verzerrtes Denken. Sie ist eine erlernte Reaktion auf echte Unsicherheit.`,
    `Diese Unterscheidung ist für die Behandlung enorm wichtig. Wenn Angst sekundär zu ADHS ist – angetrieben durch den angesammelten Stress eines ungesteuerten Aufmerksamkeitssystems – reduziert die Behandlung von ADHS oft die Angst erheblich. Systeme einzurichten, das Chaos des Alltags zu reduzieren und mehr Vorhersehbarkeit in Routinen einzubauen, kann das Bedrohungserkennungssystem beruhigen, weil weniger echte Bedrohungen vorhanden sind. Wenn Angst aber unabhängig und neurologisch ist, braucht sie möglicherweise ihre eigene gezielte Unterstützung. Ein Kliniker, der beides versteht, ist unerlässlich, um herauszufinden, was was ist.`,
    `Im Alltag sieht die Überschneidung wie eine spezifische Art von Lähmung aus: handeln wollen, aber zu viel Angst haben, es falsch zu machen; Aufgaben zu meiden, nicht nur wegen ADHS-Trägheit, sondern aus Angst vor Versagen oder Urteil; und das anhaltende Gefühl, zurückzuliegen, überfordert zu sein und nicht aufholen zu können. Perfektionismus ist oft die Brücke – das ADHS-Gehirn, das Schwierigkeiten hat anzufangen, und das ängstliche Gehirn, das sich nicht mit Unvollkommenem abfindet, erzeugen eine mächtige Zwickmühle.`,
    `Das Verstehen der Überschneidung ist der erste Schritt, um mit ihr zu arbeiten statt in ihr gefangen zu sein. Es erfordert nicht, dass man perfekt auseinanderhält, welches Symptom zu welchem Zustand gehört. Es erfordert, genug externe Struktur aufzubauen, damit das ADHS-System weniger chaotisch ist, genug Selbstmitgefühl, damit das ängstliche System aufhört, jeden Fehler als Beweis für Unzulänglichkeit zu behandeln, und genug Unterstützung – professionell, praktisch oder sozial –, um das alles nicht alleine tragen zu müssen.`,
  ],
  'adhd-sensory-sensitivity': [
    `Wenn du bestimmte Geräusche unerträglich findest, Texturen nicht ertragen kannst, helles Licht wirklich schmerzhaft ist oder belebte Umgebungen so überwältigend sind, dass du Stunden brauchst, um dich davon zu erholen, hast du dich vielleicht gefragt, ob du einfach ungewöhnlich empfindlich bist – oder ob noch etwas anderes passiert. Für viele Menschen mit ADHS ist sensorische Empfindlichkeit ein realer und bedeutsamer Teil des Alltags, auch wenn sie selten auf der Standard-Diagnoseliste erscheint. Sie ist offiziell kein diagnostisches Kriterium, wird aber von einem großen Anteil der Menschen mit ADHS erlebt, und zu verstehen, warum sie passiert, kann einen erheblichen Unterschied darin machen, wie man die Welt navigiert.`,
    `Die neurologische Erklärung beginnt mit demselben System an der Wurzel von allem anderen bei ADHS: der Regulierung von Erregung und Aufmerksamkeit. Das ADHS-Gehirn hat Schwierigkeiten zu filtern, was relevant ist von dem, was es nicht ist – und dieses Filterproblem gilt genauso für sensorische Eingaben wie für Gedanken, Aufgaben und Ablenkungen. Die meisten neurotypischen Gehirne lernen, sensorische Informationen in den Hintergrund zu drängen, die für die aktuelle Aufgabe nicht relevant sind. Das Summen des Kühlschranks, das Gefühl von Kleidung auf der Haut, das Umgebungsgeräusch eines gemeinsamen Büros – diese Dinge verblassen aus dem Bewusstsein, weil das Gehirn gelernt hat, sie zu deprioritisieren. Für viele ADHS-Gehirne ist dieses Filtern weniger effizient, sodass mehr sensorische Eingaben im Vordergrund bleiben und mit allem anderen um Aufmerksamkeit konkurrieren.`,
    `Das erzeugt eine besondere Art von Überlastung. In einem lauten Restaurant kann eine neurotypische Person ein Gespräch führen und dabei weitgehend das Hintergrundgeräusch ignorieren. Eine Person mit ADHS-sensorischer Empfindlichkeit könnte das Hintergrundgeräusch in gleicher Intensität wie das Gespräch wahrnehmen, was beides schwer gleichzeitig zu verarbeiten macht. In einem kratzenden Pullover passen sich die meisten Menschen innerhalb von Minuten an. Eine Person mit ADHS-sensorischer Empfindlichkeit könnte ihn die gesamte Zeit ablenken oder belasten. Das sind keine Charakterschwächen oder dramatische Reaktionen. Sie sind das Sinneswahrnehmungssystem, das genau das tut, was das ADHS-Gehirn in jedem anderen Bereich tut: es scheitert daran, Signal effizient von Rauschen zu trennen.`,
    `Sensorische Empfindlichkeit bei ADHS verbindet sich auch mit emotionaler Dysregulation. Hohe Sinnesbelastung erhöht die allgemeine Aktivierung des Nervensystems, was emotionale Regulierung schwerer macht. Wenn du den ganzen Morgen schon von Lärm, Licht und Texturen überwältigt wurdest, ist deine Kapazität, ruhig zu bleiben, wenn am Nachmittag etwas schiefgeht, wirklich geringer. Diesen Kaskaden-Effekt zu erkennen ist nützlich – es ist nicht so, dass du wahllos reizbar wirst, sondern dein Nervensystem ist den ganzen Tag heiß gelaufen und hat weniger Reserven übrig.`,
    `Den Umgang mit sensorischer Empfindlichkeit beginnt damit, sie als real und accommodierenswert anzuerkennen. Geräuschunterdrückende Kopfhörer sind nicht asozial; sie sind Unterstützung des Nervensystems. Kleidung nach Textur vor Ästhetik zu wählen ist keine Pingeligkeit; es ist das Beseitigen einer täglichen Dysregulationsquelle. Stille Erholungszeit nach Hochstimulations-Ereignissen einzuplanen ist keine Schwäche; es ist Wartung. So wie du eine ADHS-unfreundliche Aufgabe verwalten würdest, indem du die Reibung drum herum reduzierst, verwaltest du ein sensorisch empfindliches Nervensystem, indem du unnötige Belastung reduzierst.`,
    `Es hilft auch, darüber zu kommunizieren – mit Partnern, Mitbewohnern, Kollegen und Freunden. Sensorische Empfindlichkeit kann von außen wie Pingeligsein, Introversion oder Launenhaftigkeit aussehen, und das Missverhältnis zwischen dem, was intern passiert, und wie es von außen wirkt, ist eine häufige Reibungsquelle. Wenn Menschen verstehen, dass dein Nervensystem mehr Eingaben verarbeitet als ihres und dass das Managen dieser Eingaben echte Selbstfürsorge und nicht bloße Präferenz ist, verändert das das Gespräch erheblich.`,
  ],
}
for (const [slug, paras] of Object.entries(NEW5_DE)) {
  articleBody[slug] = { ...(articleBody[slug] || {}), de: paras }
}

const NEW5_FR: Record<string, string[]> = {
  'adhd-emotional-dysregulation': [
    `Si tu as un TDAH, on t'a probablement dit à un moment ou un autre que tu étais trop sensible, trop intense, ou que tu surréagissais. Ce que la plupart des gens — et beaucoup de cliniciens — ne réalisent pas, c'est que la dysrégulation émotionnelle n'est pas un trait de caractère superposé au TDAH. C'est l'une de ses caractéristiques les plus centrales et les moins discutées. Le cerveau TDAH ne lutte pas seulement avec l'attention et le contrôle des impulsions. Il lutte pour réguler l'ampleur et la durée des réponses émotionnelles, ce qui signifie que les sentiments arrivent plus vite, frappent plus fort et durent plus longtemps que chez la plupart des gens.`,
    `La neuroscience aide à expliquer pourquoi. Le cortex préfrontal — la partie du cerveau responsable de modérer les réponses émotionnelles, de faire une pause avant de réagir et de contextualiser les sentiments — est la même zone la plus touchée par le TDAH. Quand ce système est sous-actif, les centres émotionnels du cerveau, notamment l'amygdale, s'activent sans freinage adéquat. Le résultat n'est pas que les cerveaux TDAH ressentent plus que les autres. C'est qu'ils ressentent sans le tampon habituel entre sentir et réagir.`,
    `Cela se manifeste selon quelques schémas reconnaissables. La frustration peut escalader jusqu'à la rage en quelques secondes, pour quelque chose qui paraît mineur vu de l'extérieur. L'excitation peut basculer en décisions impulsives ou une pensée éparpillée. La déception peut glisser vers des heures de moral bas qui ressemble à de la dépression mais se lève de façon inattendue. Et les transitions — passer d'un état émotionnel, d'une tâche ou d'un environnement à un autre — peuvent être vraiment déstabilisantes, parce que le système nerveux n'a pas fini de traiter la dernière chose.`,
    `Ce qui rend cela particulièrement douloureux, c'est le décalage entre l'expérience intérieure et la perception extérieure. La personne avec un TDAH sait que le sentiment est intense ; elle sait aussi généralement, intellectuellement, que la réaction pourrait être disproportionnée. Mais le savoir n'aide pas sur le moment, parce que c'est exactement le système de freinage qui ne fonctionne pas. La honte qui suit — pour avoir explosé, pleuré, dit quelque chose d'impulsif — aggrave souvent la difficulté initiale et devient sa propre source de dysrégulation.`,
    `Ce qui aide vraiment, c'est de créer un espace entre le stimulus et la réaction — non par la volonté, qui est trop lente, mais par des stratégies physiques et environnementales. Nommer l'émotion à voix haute crée une toute petite pause. Quitter la situation avant l'escalade plutôt qu'après donne au système nerveux le temps de se réinitialiser. L'eau froide, le mouvement ou la respiration lente peuvent déplacer l'état physiologique directement. Et travailler avec un thérapeute sur la reconnaissance émotionnelle et les schémas de réponse aide à moyen terme, non en apprenant à supprimer les sentiments, mais en les rendant plus lisibles en temps réel.`,
    `Avant tout, comprendre que la dysrégulation émotionnelle est neurologique plutôt que morale change l'ensemble du tableau. Tu n'es pas trop. Tu n'es pas faible. Tu as un cerveau qui ressent les choses à plein volume, et cette même intensité, quand elle n'est pas sous pression, est souvent la source de ton empathie, ta créativité et ta capacité à prendre soin profondément. Le but n'est pas de ressentir moins. C'est de construire assez de soutien autour de ces sentiments pour qu'ils arrêtent de conduire la voiture.`,
  ],
  'adhd-hyperfocus': [
    `L'une des choses les plus déroutantes avec le TDAH, c'est qu'il ne ressemble pas à un déficit d'attention quand tu es plongé·e depuis quatre heures dans quelque chose que tu aimes, ayant complètement oublié de manger, de boire, ou de remarquer qu'il fait nuit dehors. C'est l'hyperfocus : l'absorption intense et involontaire dans une tâche ou un sujet qui peut faire ressembler le TDAH, vu de l'extérieur, à son propre contraire. Et c'est autant un symptôme que la distractibilité — c'est juste le symptôme dont personne ne te prévient.`,
    `L'hyperfocus se produit parce que le cerveau TDAH ne manque pas vraiment d'attention. Il manque de la capacité à réguler où l'attention va. Dans les cerveaux neurotypiques, l'attention est guidée par la priorité et l'intention. Dans les cerveaux TDAH, elle est guidée principalement par l'intérêt et la stimulation. Quand quelque chose capture vraiment cet intérêt — un projet créatif, un jeu vidéo, une spirale de recherche, une nouvelle obsession — le cerveau est inondé de dopamine et se verrouille. Le monde extérieur cesse d'être perçu. Le temps disparaît. Tout ce qui n'est pas la chose devient invisible.`,
    `Ça ressemble à un superpouvoir, et parfois c'en est un. L'hyperfocus peut produire une output extraordinaire, une expertise profonde, et le type d'absorption créative qui génère un vrai travail de qualité. Mais il a un côté sombre. Tu ne peux pas le convoquer de façon fiable pour les choses qui comptent le plus. Tu peux te perdre complètement dans quelque chose de peu important pendant que des délais critiques passent. Les transitions hors de l'hyperfocus sont souvent brutales — le cerveau résiste à être ramené, ce qui peut ressembler à une résistance émotionnelle ou un effondrement. Et le crash ensuite, quand la dopamine chute, peut ressembler à une légère dépression.`,
    `L'hyperfocus n'est pas non plus la même chose que le flow, même s'ils se ressentent de façon similaire. Le flow, tel que décrit en psychologie, est un état qu'on peut entrer intentionnellement avec le bon niveau de défi. L'hyperfocus tend à être involontaire, plus difficile à quitter, et pas toujours connecté à quelque chose que la personne veut vraiment prioriser. La distinction importe parce que les stratégies pour le flow ne se transposent pas toujours à la gestion de l'hyperfocus.`,
    `Travailler avec l'hyperfocus plutôt que contre lui signifie quelques choses en pratique. Régler une alarme avant de commencer quelque chose d'absorbant donne au cerveau un signal de sortie qu'il n'a pas créé lui-même et donc auquel il doit répondre. Garder les tâches à haut intérêt pour des moments où tu peux te permettre de t'y perdre — soirées, blocs libres — protège le reste de ton emploi du temps. Et construire un court rituel de transition quand tu dois t'arrêter — une descente de cinq minutes, une brève note sur où tu en es, une courte pause de mouvement — aide le système nerveux à changer de vitesse plutôt que de les meuler.`,
    `Comprendre l'hyperfocus aide aussi avec le jugement de soi. Le même cerveau qui ne peut pas commencer la déclaration d'impôts peut écrire six heures sans pause. Ce n'est pas de l'inconsistance. C'est le système d'attention TDAH qui fait exactement ce qu'il fait : suivre l'intérêt, pas l'importance. Le but n'est pas de se débarrasser de l'hyperfocus, mais de construire assez d'échafaudage autour de lui pour qu'il devienne un atout qu'on peut surtout diriger, plutôt qu'une force qui t'arrive juste dessus.`,
  ],
  'adhd-executive-dysfunction': [
    `La dysfonction exécutive est l'un de ces termes qui sonnent cliniques et abstraits jusqu'à ce qu'on en fasse l'expérience — et alors il sonne exactement juste. C'est l'expérience de savoir précisément ce qu'on doit faire, d'avoir la capacité de le faire, de le vouloir — et de trouver que la partie du cerveau responsable d'amorcer l'action ne coopère tout simplement pas. Ce n'est pas de la paresse. Ce n'est pas un mauvais caractère. C'est une difficulté neurologique spécifique avec l'ensemble des compétences qui permettent aux humains de planifier, commencer, séquencer, surveiller et compléter un comportement orienté vers un but.`,
    `Ces compétences résident principalement dans le cortex préfrontal, le centre de commandement du cerveau pour organiser la pensée et l'action. Dans les cerveaux TDAH, ce système se développe plus lentement et fonctionne différemment — pas dans chaque contexte, et pas de façon égale chaque jour, mais assez pour que les tâches nécessitant une auto-direction soutenue soient systématiquement plus difficiles qu'elles ne devraient l'être. La difficulté n'est pas avec l'intelligence, la compréhension ou même la motivation dans l'abstrait. Elle est avec la machinerie neurologique qui traduit l'intention en action.`,
    `La dysfonction exécutive se manifeste différemment selon les personnes et les situations. Pour certains, c'est le démarrage des tâches — l'énergie d'activation requise pour commencer semble impossiblement haute, surtout pour des tâches ennuyeuses, peu claires ou sans récompense immédiate. Pour d'autres, c'est le passage entre les tâches — les transitions semblent laborieuses, et le cerveau résiste à lâcher ce sur quoi il travaille déjà. Pour d'autres encore, c'est la mémoire de travail — la capacité à tenir des informations en tête pendant qu'on les utilise — si bien que les instructions se perdent, les étapes sautent, et les tâches complexes à plusieurs parties deviennent un mur.`,
    `L'inconsistance est l'un des aspects les plus douloureux et les moins compris. La fonction exécutive dans le TDAH n'est pas uniformément altérée. Quand quelque chose est vraiment intéressant, urgent, nouveau ou émotionnellement chargé, le cerveau peut produire une fonction exécutive qui paraît totalement typique. C'est pourquoi le TDAH passe souvent inaperçu, et pourquoi les personnes avec un TDAH internalisent souvent la conclusion qu'elles pourraient toujours faire la chose si elles essayaient assez fort. La vérité est que le même cerveau qui écrit brillamment à minuit sous une deadline ne peut pas écrire le même texte de façon fiable à 10h du matin avec tout le temps du monde. Le contexte fait beaucoup du travail que la fonction exécutive fait habituellement.`,
    `Travailler avec la dysfonction exécutive signifie externaliser autant que possible. Les listes de tâches écrites, les minuteries, les calendriers visuels et les rappels physiques font tous le travail de tenir la structure que le cerveau ne fait pas de façon fiable en interne. Décomposer les tâches en étapes les plus petites possibles supprime le fardeau de planification du moment du démarrage. Utiliser le body doubling, la musique ou des indices environnementaux pour signaler au cerveau qu'il est temps de travailler emprunte la structure de l'extérieur quand l'intérieur ne la génère pas. Ce ne sont pas des contournements d'un déficit — c'est ainsi que le cerveau fonctionne le mieux.`,
    `Le recadrage le plus important est que la dysfonction exécutive n'est pas une mesure de ton potentiel, ton intelligence ou ta valeur. Certaines des personnes les plus capables, créatives et dévouées au monde ont une dysfonction exécutive significative. Ce qu'elles ont en commun, ce n'est pas qu'elles l'ont surmontée par la volonté, mais qu'elles ont construit des environnements et des systèmes qui fonctionnaient avec le cerveau qu'elles avaient. C'est le vrai objectif : pas plus dur, mais plus intelligent — structurer la vie pour que le cerveau puisse faire ce qu'il fait le mieux.`,
  ],
  'adhd-and-anxiety': [
    `Le TDAH et l'anxiété se retrouvent si souvent ensemble que des chercheurs ont passé des décennies à essayer de démêler lequel vient en premier, s'ils partagent une racine commune, ou si l'un cause simplement l'autre. La réponse honnête est : c'est compliqué, et ça varie probablement d'une personne à l'autre. Ce qui est clair, c'est que les deux ensemble n'est pas inhabituel — les estimations suggèrent qu'environ la moitié des adultes avec un TDAH répondent aussi aux critères d'un trouble anxieux — et que traiter l'un sans reconnaître l'autre laisse un écart significatif.`,
    `Une partie de la connexion est neurologique. Le TDAH et l'anxiété impliquent tous deux une dysrégulation des systèmes dopaminergique et noradrénergique qui gouvernent l'attention, la réponse émotionnelle et la détection des menaces. Les cerveaux TDAH tendent à sous-réagir à la stimulation de bas niveau et à chercher la nouveauté ; les cerveaux anxieux tendent à sur-réagir aux indices de menace et à catastrophiser les risques. Quand ces deux systèmes sont tous les deux perturbés chez la même personne, le résultat peut être un cerveau simultanément attiré par la stimulation et terrorisé par les conséquences — un schéma qui produit un type particulier de conflit interne épuisant.`,
    `Une partie de la connexion est aussi expérientielle. Des années de délais manqués, d'engagements oubliés, de décisions impulsives et d'erreurs sociales créent une base très rationnelle pour l'anxiété. Quand on a appris que son cerveau est imprévisible, que des choses importantes peuvent passer à travers les mailles sans avertissement, et que les autres sont souvent confus ou frustrés par son comportement, la vigilance commence à sembler la seule réponse sensée. L'anxiété, dans ce cas, n'est pas une pensée déformée. C'est une réponse apprise à une véritable incertitude.`,
    `Cette distinction est d'une importance énorme pour le traitement. Si l'anxiété est secondaire au TDAH — alimentée par le stress accumulé d'un système d'attention non géré — alors gérer le TDAH réduit souvent l'anxiété de façon significative. Mettre des systèmes en place, réduire le chaos de la vie quotidienne, et construire plus de prévisibilité dans les routines peuvent calmer le système de détection des menaces parce qu'il y a moins de vraies menaces. Mais si l'anxiété est indépendante et neurologique, elle peut nécessiter son propre soutien ciblé. Un clinicien qui comprend les deux est essentiel pour travailler à distinguer ce qui est quoi.`,
    `Dans la vie quotidienne, le chevauchement ressemble à un type spécifique de paralysie : vouloir agir mais trop peur de mal faire ; éviter les tâches non seulement par inertie TDAH mais par peur de l'échec ou du jugement ; et un sentiment persistant d'être en retard, débordé et incapable de rattraper. Le perfectionnisme est souvent le pont — le cerveau TDAH qui du mal à commencer et le cerveau anxieux qui ne se contentera pas d'un résultat imparfait créent une double contrainte puissante.`,
    `Comprendre le chevauchement est la première étape pour travailler avec lui plutôt que d'être coincé dedans. Cela ne nécessite pas de trier parfaitement quel symptôme appartient à quelle condition. Cela nécessite de construire assez de structure externe pour que le système TDAH soit moins chaotique, assez d'auto-compassion pour que le système anxieux cesse de traiter chaque erreur comme une preuve d'insuffisance, et assez de soutien — professionnel, pratique ou social — pour ne pas avoir à tout porter seul.`,
  ],
  'adhd-sensory-sensitivity': [
    `Si tu trouves certains sons insupportables, certaines textures intolérables, si les lumières vives te font vraiment souffrir, ou si les environnements bondés sont si accablants que tu as besoin d'heures pour t'en remettre, tu t'es peut-être demandé si tu es juste inhabituellement sensible — ou s'il se passe autre chose. Pour beaucoup de personnes avec un TDAH, la sensibilité sensorielle est une partie réelle et significative de la vie quotidienne, même si elle apparaît rarement sur la liste de contrôle diagnostique standard. Ce n'est pas officiellement un critère diagnostique, mais elle est vécue par une grande proportion de personnes avec un TDAH, et comprendre pourquoi elle se produit peut faire une différence significative dans la façon dont on navigue dans le monde.`,
    `L'explication neurologique part du même système à la racine de tout le reste dans le TDAH : la régulation de l'éveil et de l'attention. Le cerveau TDAH a du mal à filtrer ce qui est pertinent de ce qui ne l'est pas — et ce problème de filtrage s'applique aux entrées sensorielles tout autant qu'aux pensées, aux tâches et aux distractions. La plupart des cerveaux neurotypiques apprennent à mettre en arrière-plan les informations sensorielles qui ne sont pas pertinentes pour la tâche. Le bourdonnement du réfrigérateur, la sensation des vêtements sur la peau, le bruit ambiant d'un bureau partagé — ces choses s'effacent de la conscience parce que le cerveau a appris à les déprioritiser. Pour beaucoup de cerveaux TDAH, ce filtrage est moins efficace, donc plus d'entrées sensorielles restent au premier plan, en compétition pour l'attention avec tout le reste.`,
    `Cela crée un type particulier de surcharge. Dans un restaurant bruyant, une personne neurotypique peut avoir une conversation tout en ignorant surtout le bruit de fond. Une personne avec une sensibilité sensorielle TDAH pourrait trouver le bruit de fond d'égale intensité à la conversation, rendant les deux difficiles à traiter simultanément. Dans un pull rayeux, la plupart des gens s'adaptent en quelques minutes. Une personne avec une sensibilité sensorielle TDAH pourrait le trouver distrayant ou pénible pendant toute la durée du port. Ce ne sont pas des faiblesses de caractère ou des réponses dramatiques. Ce sont le système sensoriel qui fait exactement ce que le cerveau TDAH fait dans tous les autres domaines : ne pas réussir à trier efficacement le signal du bruit.`,
    `La sensibilité sensorielle dans le TDAH se connecte aussi à la dysrégulation émotionnelle. Une charge sensorielle élevée augmente l'éveil général du système nerveux, ce qui rend la régulation émotionnelle plus difficile. Si tu as déjà été submergé·e par le bruit, la lumière et les textures toute la matinée, ta capacité à rester calme quand quelque chose va mal dans l'après-midi est réellement plus faible. Reconnaître cette cascade est utile — ce n'est pas que tu deviennes irritable aléatoirement, mais que ton système nerveux tourne chaud toute la journée et a moins de réserves.`,
    `Gérer la sensibilité sensorielle commence par la reconnaître comme réelle et valant la peine d'être accommodée. Les écouteurs antibruit ne sont pas asociaux ; ce sont des supports pour le système nerveux. Choisir les vêtements par texture avant l'esthétique n'est pas de la maniaquerie ; c'est éliminer une source quotidienne de dysrégulation. Prévoir du temps de récupération calme après des événements à haute stimulation n'est pas une faiblesse ; c'est de l'entretien. De la même façon qu'on gérerait une tâche défavorable au TDAH en réduisant la friction autour d'elle, on gère un système nerveux à sensibilité sensorielle en réduisant la charge inutile.`,
    `Ça aide aussi d'en parler — avec des partenaires, des colocataires, des collègues et des amis. La sensibilité sensorielle peut ressembler, vu de l'extérieur, à de la pinaillerie, de l'introversion ou de la maussaderie, et le décalage entre ce qui se passe intérieurement et comment ça se lit extérieurement est une source courante de friction. Quand les gens comprennent que ton système nerveux traite plus d'entrées que le leur, et que gérer ces entrées est un vrai soin de soi plutôt qu'une préférence, ça change généralement la conversation de façon significative.`,
  ],
}
for (const [slug, paras] of Object.entries(NEW5_FR)) {
  articleBody[slug] = { ...(articleBody[slug] || {}), fr: paras }
}

const NEW5_ES: Record<string, string[]> = {
  'adhd-emotional-dysregulation': [
    `Si tienes TDAH, probablemente te hayan dicho en algún momento que eres demasiado sensible·a, demasiado intenso·a, o que reaccionas de forma exagerada. Lo que la mayoría de las personas, y muchos clínicos, no se dan cuenta es que la desregulación emocional no es un rasgo de personalidad superpuesto al TDAH. Es una de sus características más centrales y menos discutidas. El cerebro con TDAH no solo lucha con la atención y el control de impulsos. Lucha para regular el tamaño y la duración de las respuestas emocionales, lo que significa que los sentimientos llegan más rápido, golpean más fuerte y duran más que en la mayoría de las personas.`,
    `La neurociencia ayuda a explicar por qué. El córtex prefrontal, la parte del cerebro responsable de moderar las respuestas emocionales, de hacer una pausa antes de reaccionar y de poner los sentimientos en contexto, es la misma zona más afectada por el TDAH. Cuando ese sistema está poco activo, los centros emocionales del cerebro, en particular la amígdala, se activan sin freno adecuado. El resultado no es que los cerebros con TDAH sientan más que los demás. Es que sienten sin el amortiguador habitual entre sentir y reaccionar.`,
    `Esto se manifiesta en unos patrones reconocibles. La frustración puede escalar hasta la rabia en segundos, por algo que parece menor desde fuera. La excitación puede derivar en decisiones impulsivas o pensamiento disperso. La decepción puede deslizarse hacia horas de ánimo bajo que parecen depresión pero se levantan inesperadamente. Y las transiciones, pasar de un estado emocional, una tarea o un entorno a otro, pueden ser genuinamente desestabilizadoras, porque el sistema nervioso no ha terminado de procesar lo último.`,
    `Lo que hace esto especialmente doloroso es el desajuste entre la experiencia interna y la percepción externa. La persona con TDAH sabe que el sentimiento es intenso; también suele saber, intelectualmente, que la reacción puede ser desproporcionada. Pero saberlo no ayuda en el momento, porque el sistema de freno es exactamente lo que no funciona. La vergüenza que sigue, por haber explotado, llorado, dicho algo impulsivo, a menudo agrava la dificultad original y se convierte en su propia fuente de desregulación.`,
    `Lo que realmente ayuda es crear un espacio entre el estímulo y la respuesta, no mediante la fuerza de voluntad, que es demasiado lenta, sino a través de estrategias físicas y ambientales. Nombrar la emoción en voz alta crea una pequeña pausa. Abandonar la situación antes de la escalada en lugar de después le da al sistema nervioso tiempo para reiniciarse. El agua fría, el movimiento o la respiración lenta pueden cambiar el estado fisiológico directamente. Y trabajar con un terapeuta en el reconocimiento emocional y los patrones de respuesta ayuda a medio plazo, no enseñando a suprimir los sentimientos, sino haciéndolos más legibles en tiempo real.`,
    `Sobre todo, entender que la desregulación emocional es neurológica y no moral cambia todo el panorama. No eres demasiado·a. No eres débil·. Tienes un cerebro que siente las cosas a todo volumen, y esa misma intensidad, cuando no está bajo presión, es a menudo la fuente de tu empatía, tu creatividad y tu capacidad de cuidar profundamente. El objetivo no es sentir menos. Es construir suficiente apoyo alrededor de esos sentimientos para que dejen de conducir el coche.`,
  ],
  'adhd-hyperfocus': [
    `Una de las cosas más desconcertantes del TDAH es que no parece un déficit de atención cuando llevas cuatro horas profundamente absorto·a en algo que amas, habiendo olvidado por completo comer, beber o notar que ya es de noche. Esto es el hiperfoco: la absorción intensa e involuntaria en una tarea o tema que puede hacer que el TDAH parezca, desde fuera, lo contrario de sí mismo. Y es tanto un síntoma como la distractibilidad: es simplemente el síntoma del que nadie te advierte.`,
    `El hiperfoco ocurre porque el cerebro con TDAH no tiene en realidad escasez de atención. Tiene escasez de la capacidad de regular hacia dónde va la atención. En los cerebros neurotípicos, la atención está guiada por la prioridad y la intención. En los cerebros con TDAH, está guiada principalmente por el interés y la estimulación. Cuando algo captura genuinamente ese interés, un proyecto creativo, un videojuego, una espiral de investigación, una nueva obsesión, el cerebro se inunda de dopamina y se engancha. El mundo exterior deja de percibirse. El tiempo desaparece. Todo lo que no es la cosa se vuelve invisible.`,
    `Suena como una superpotencia, y a veces lo es. El hiperfoco puede producir un output extraordinario, una experiencia profunda y el tipo de absorción creativa que genera trabajo genuinamente bueno. Pero tiene un lado oscuro. No puedes convocarlo de forma fiable para las cosas que más importan. Puedes perderte completamente en algo sin importancia mientras plazos críticos pasan de largo. Las transiciones fuera del hiperfoco suelen ser brutales: el cerebro resiste ser devuelto, lo que puede parecer resistencia emocional o colapso. Y el bajón posterior, cuando la dopamina cae, puede sentirse como una leve depresión.`,
    `El hiperfoco tampoco es lo mismo que el flujo, aunque se sienten de manera similar. El flujo, tal como lo describe la psicología, es un estado al que se puede entrar intencionalmente con el nivel adecuado de desafío. El hiperfoco tiende a ser involuntario, más difícil de salir, y no siempre conectado a algo que la persona realmente quiere priorizar. La distinción importa porque las estrategias para el flujo no siempre se trasladan a la gestión del hiperfoco.`,
    `Trabajar con el hiperfoco en lugar de contra él significa algunas cosas en la práctica. Poner una alarma antes de empezar algo absorbente le da al cerebro una señal de salida que no creó él mismo y a la que por tanto debe responder. Reservar las tareas de alto interés para momentos en que puedes permitirte perderte en ellas, tardes, bloques libres, protege el resto de tu horario. Y construir un breve ritual de transición cuando tienes que parar, una desaceleración de cinco minutos, una breve nota sobre dónde estás, una corta pausa de movimiento, ayuda al sistema nervioso a cambiar de marcha en lugar de rechinarlas.`,
    `Entender el hiperfoco también ayuda con el autojuicio. El mismo cerebro que no puede empezar la declaración de impuestos puede escribir durante seis horas sin parar. Eso no es inconsistencia. Es el sistema de atención del TDAH haciendo exactamente lo que hace: seguir el interés, no la importancia. El objetivo no es deshacerse del hiperfoco, sino construir suficiente andamiaje a su alrededor para que se convierta en un activo que puedes principalmente dirigir, en lugar de una fuerza que simplemente te ocurre.`,
  ],
  'adhd-executive-dysfunction': [
    `La disfunción ejecutiva es uno de esos términos que suenan clínicos y abstractos hasta que lo experimentas, y entonces suena exactamente bien. Es la experiencia de saber precisamente lo que tienes que hacer, tener la capacidad de hacerlo, querer hacerlo, y encontrar que la parte de tu cerebro responsable de iniciarlo simplemente no coopera. No es pereza. No es mal carácter. Es una dificultad neurológica específica con el conjunto de habilidades que permiten a los humanos planificar, comenzar, secuenciar, supervisar y completar un comportamiento orientado a metas.`,
    `Esas habilidades residen principalmente en el córtex prefrontal, el centro de mando del cerebro para organizar el pensamiento y la acción. En los cerebros con TDAH, este sistema se desarrolla más lentamente y funciona de manera diferente, no en todos los contextos, y no de igual forma cada día, pero lo suficiente como para que las tareas que requieren auto-dirección sostenida sean consistentemente más difíciles de lo que deberían. La dificultad no está con la inteligencia, la comprensión o incluso la motivación en abstracto. Está con la maquinaria neurológica que traduce la intención en acción.`,
    `La disfunción ejecutiva se manifiesta de manera diferente en personas y situaciones. Para algunos es iniciar tareas: la energía de activación requerida para empezar parece imposiblemente alta, especialmente para tareas aburridas, poco claras o sin recompensa inmediata. Para otros es cambiar entre tareas: las transiciones se sienten laboriosas y el cerebro resiste soltar lo que ya está haciendo. Para otros más es la memoria de trabajo: la capacidad de retener información en la mente mientras se usa, de modo que las instrucciones se pierden, los pasos se saltan y las tareas complejas de varias partes se convierten en un muro.`,
    `La inconsistencia es uno de los aspectos más dolorosos y menos comprendidos. La función ejecutiva en el TDAH no está uniformemente deteriorada. Cuando algo es genuinamente interesante, urgente, novedoso o emocionalmente cargado, el cerebro puede producir una función ejecutiva que parece completamente típica. Por eso el TDAH a menudo pasa desapercibido, y por eso las personas con TDAH a menudo internalizan la conclusión de que siempre podrían hacer la cosa si se esforzaran lo suficiente. La verdad es que el mismo cerebro que escribe brillantemente a medianoche bajo una fecha límite no puede escribir de forma fiable el mismo texto a las 10 de la mañana con todo el tiempo del mundo. El contexto está haciendo mucho del trabajo que la función ejecutiva normalmente hace.`,
    `Trabajar con la disfunción ejecutiva significa externalizar tanto como sea posible. Las listas de tareas escritas, los temporizadores, los horarios visuales y los recordatorios físicos hacen el trabajo de mantener la estructura que el cerebro no hace de forma fiable internamente. Dividir las tareas en los pasos más pequeños posibles elimina la carga de planificación del momento de inicio. Usar el body doubling, la música o señales ambientales para indicarle al cerebro que es hora de trabajar toma prestada la estructura del exterior cuando el interior no la genera. Nada de esto es una solución alternativa para un déficit: es cómo el cerebro realmente funciona mejor.`,
    `El reencuadre más importante es que la disfunción ejecutiva no es una medida de tu potencial, tu inteligencia o tu valía. Algunas de las personas más capaces, creativas y dedicadas del mundo tienen una disfunción ejecutiva significativa. Lo que tienen en común no es que la superaron a través de la fuerza de voluntad, sino que construyeron entornos y sistemas que funcionaban con el cerebro que tenían. Ese es el objetivo real: no más duro, sino más inteligente, estructurar la vida para que el cerebro pueda hacer lo que mejor hace.`,
  ],
  'adhd-and-anxiety': [
    `El TDAH y la ansiedad se encuentran juntos con tanta frecuencia que los investigadores han pasado décadas intentando desenredar cuál viene primero, si comparten una raíz común o si uno simplemente causa el otro. La respuesta honesta es: es complicado, y probablemente varía de persona a persona. Lo que está claro es que tener ambos no es inusual: las estimaciones sugieren que alrededor de la mitad de los adultos con TDAH también cumplen criterios para un trastorno de ansiedad, y que tratar uno sin reconocer el otro deja una brecha significativa.`,
    `Parte de la conexión es neurológica. Tanto el TDAH como la ansiedad implican desregulación en los sistemas de dopamina y norepinefrina que gobiernan la atención, la respuesta emocional y la detección de amenazas. Los cerebros con TDAH tienden a reaccionar poco ante la estimulación de bajo nivel y a buscar novedad; los cerebros ansiosos tienden a reaccionar en exceso ante las señales de amenaza y a catastrofizar el riesgo. Cuando ambos sistemas están perturbados en la misma persona, el resultado puede ser un cerebro simultáneamente atraído por la estimulación y aterrorizado por las consecuencias, un patrón que produce un tipo particular de conflicto interno agotador.`,
    `Parte de la conexión es también experiencial. Años de plazos incumplidos, compromisos olvidados, decisiones impulsivas y errores sociales crean una base muy racional para la ansiedad. Cuando has aprendido que tu cerebro es impredecible, que cosas importantes pueden colarse por las grietas sin previo aviso, y que los demás a menudo están confundidos o frustrados por tu comportamiento, la vigilancia empieza a sentirse como la única respuesta sensata. La ansiedad, en este caso, no es pensamiento distorsionado. Es una respuesta aprendida ante una incertidumbre genuina.`,
    `Esta distinción importa enormemente para el tratamiento. Si la ansiedad es secundaria al TDAH, impulsada por el estrés acumulado de un sistema de atención no gestionado, entonces manejar el TDAH a menudo reduce la ansiedad de forma significativa. Establecer sistemas, reducir el caos de la vida diaria y construir más predictibilidad en las rutinas puede calmar el sistema de detección de amenazas porque hay menos amenazas genuinas. Pero si la ansiedad es independiente y neurológica, puede necesitar su propio apoyo específico. Un clínico que comprenda ambas es esencial para determinar cuál es cuál.`,
    `En la vida cotidiana, la superposición se parece a un tipo específico de parálisis: querer actuar pero tener demasiado miedo de hacerlo mal; evitar tareas no solo por inercia del TDAH sino por miedo al fracaso o al juicio; y una sensación persistente de ir rezagado·a, abrumado·a e incapaz de ponerse al día. El perfeccionismo es a menudo el puente: el cerebro con TDAH que tiene dificultades para empezar y el cerebro ansioso que no se conforma con un resultado imperfecto crean una poderosa trampa doble.`,
    `Entender la superposición es el primer paso para trabajar con ella en lugar de quedar atrapado·a en ella. No requiere separar perfectamente qué síntoma pertenece a qué condición. Requiere construir suficiente estructura externa para que el sistema del TDAH sea menos caótico, suficiente autocompasión para que el sistema ansioso deje de tratar cada error como evidencia de insuficiencia, y suficiente apoyo, profesional, práctico o social, para no tener que cargarlo todo solo·a.`,
  ],
  'adhd-sensory-sensitivity': [
    `Si encuentras ciertos sonidos insoportables, ciertas texturas intolerables, si las luces brillantes te resultan genuinamente dolorosas o los entornos concurridos tan abrumadores que necesitas horas para recuperarte después, puede que te hayas preguntado si simplemente eres inusualmente sensible·a, o si hay algo más ocurriendo. Para muchas personas con TDAH, la sensibilidad sensorial es una parte real y significativa de la vida cotidiana, aunque rara vez aparece en la lista de comprobación diagnóstica estándar. No es oficialmente un criterio diagnóstico, pero la experimenta una gran proporción de personas con TDAH, y entender por qué ocurre puede marcar una diferencia significativa en cómo se navega por el mundo.`,
    `La explicación neurológica parte del mismo sistema en la raíz de todo lo demás en el TDAH: la regulación del arousal y la atención. El cerebro con TDAH tiene dificultades para filtrar lo que es relevante de lo que no lo es, y este problema de filtrado se aplica a la entrada sensorial igual que a los pensamientos, las tareas y las distracciones. La mayoría de los cerebros neurotípicos aprenden a poner en segundo plano la información sensorial que no es relevante para la tarea. El zumbido del refrigerador, la sensación de la ropa sobre la piel, el ruido ambiental de una oficina compartida: estas cosas se desvanecen de la conciencia porque el cerebro ha aprendido a desprotegerlas. Para muchos cerebros con TDAH, este filtrado es menos eficiente, por lo que más entrada sensorial permanece en primer plano, compitiendo por la atención con todo lo demás.`,
    `Esto crea un tipo particular de sobrecarga. En un restaurante ruidoso, una persona neurotípica puede tener una conversación ignorando en su mayor parte el ruido de fondo. Una persona con sensibilidad sensorial por TDAH puede encontrar el ruido de fondo igual de intenso que la conversación, haciendo que ambos sean difíciles de procesar simultáneamente. Con un jersey que pica, la mayoría de las personas se adaptan en minutos. Una persona con sensibilidad sensorial por TDAH puede encontrarlo distrayente o angustiante durante todo el tiempo que lo lleva puesto. Estas no son debilidades de carácter ni respuestas dramáticas. Son el sistema sensorial haciendo exactamente lo que el cerebro con TDAH hace en todos los demás dominios: no lograr separar eficientemente la señal del ruido.`,
    `La sensibilidad sensorial en el TDAH también se conecta con la desregulación emocional. Una alta carga sensorial aumenta el arousal general del sistema nervioso, lo que hace más difícil la regulación emocional. Si ya has estado abrumado·a por el ruido, la luz y las texturas toda la mañana, tu capacidad para mantenerte tranquilo·a cuando algo sale mal por la tarde es genuinamente menor. Reconocer esta cascada es útil: no es que te vuelvas irritable al azar, sino que tu sistema nervioso ha estado funcionando caliente todo el día y le quedan menos reservas.`,
    `Gestionar la sensibilidad sensorial empieza por reconocerla como real y digna de ser acomodada. Los auriculares con cancelación de ruido no son antisociales; son apoyo al sistema nervioso. Elegir la ropa por la textura antes que por la estética no es manías; es eliminar una fuente diaria de desregulación. Reservar tiempo de recuperación tranquilo después de eventos de alta estimulación no es debilidad; es mantenimiento. De la misma manera en que gestionarías una tarea poco amigable con el TDAH reduciendo la fricción a su alrededor, gestionas un sistema nervioso con sensibilidad sensorial reduciendo la carga innecesaria.`,
    `También ayuda comunicarlo, con parejas, compañeros de piso, colegas y amigos. La sensibilidad sensorial puede parecer, desde fuera, exigencia, introversión o mal humor, y el desajuste entre lo que ocurre internamente y cómo se lee externamente es una fuente común de fricción. Cuando las personas entienden que tu sistema nervioso procesa más entradas que el suyo, y que gestionar esas entradas es un autocuidado genuino y no una preferencia, tiende a cambiar la conversación de manera significativa.`,
  ],
}
for (const [slug, paras] of Object.entries(NEW5_ES)) {
  articleBody[slug] = { ...(articleBody[slug] || {}), es: paras }
}
